const QUESTIONS_CHEMISTRY = [
{"id": "chem-mc-001", "t": "choice", "q": "下列物质中属于纯净物的是", "o": ["A. 空气", "B. 石灰水", "C. 冰水混合物", "D. 矿泉水"], "a": "C", "e": "冰和水的化学式都是H2O，属于同一种物质，冰水混合物是纯净物。空气、石灰水、矿泉水都是混合物。"},
{"id": "chem-mc-002", "t": "choice", "q": "下列物质属于酸性氧化物的是", "o": ["A. CO", "B. CO2", "C. Na2O", "D. H2O"], "a": "B", "e": "CO2能与碱反应生成盐和水，是酸性氧化物。CO是不成盐氧化物，Na2O是碱性氧化物，H2O是中性氧化物。"},
{"id": "chem-mc-003", "t": "choice", "q": "下列属于碱的是", "o": ["A. Na2CO3", "B. NaOH", "C. NaHCO3", "D. H2SO4"], "a": "B", "e": "碱是电离时阴离子全部是OH-的化合物。NaOH电离出Na+和OH-，是碱。Na2CO3和NaHCO3是盐，H2SO4是酸。"},
{"id": "chem-mc-004", "t": "choice", "q": "下列物质中属于盐的是", "o": ["A. HCl", "B. Ca(OH)2", "C. CaCO3", "D. H2CO3"], "a": "C", "e": "CaCO3由Ca2+和CO3^2-组成，属于盐。HCl是酸，Ca(OH)2是碱，H2CO3是酸。"},
{"id": "chem-mc-005", "t": "choice", "q": "下列属于混合物的是", "o": ["A. 胆矾", "B. 液氯", "C. 漂白粉", "D. 干冰"], "a": "C", "e": "漂白粉是Ca(ClO)2和CaCl2的混合物。胆矾CuSO4*5H2O是纯净物，液氯Cl2是纯净物，干冰CO2是纯净物。"},
{"id": "chem-mc-006", "t": "choice", "q": "下列说法正确的是", "o": ["A. 纯碱属于碱", "B. 酸性氧化物一定是非金属氧化物", "C. 碱性氧化物一定是金属氧化物", "D. 水不属于氧化物"], "a": "C", "e": "碱性氧化物都是金属氧化物。纯碱Na2CO3是盐，Mn2O7是金属氧化物但不是碱性氧化物，所以B的逆命题不对。水是氧化物。"},
{"id": "chem-mc-007", "t": "choice", "q": "下列物质属于电解质的是", "o": ["A. 蔗糖", "B. 酒精", "C. NaCl", "D. 铜"], "a": "C", "e": "NaCl在水溶液和熔融状态都能导电，是电解质。蔗糖和酒精是非电解质，铜是单质。"},
{"id": "chem-mc-008", "t": "choice", "q": "下列属于非电解质的是", "o": ["A. BaSO4", "B. HCl", "C. CO2", "D. NaOH"], "a": "C", "e": "CO2溶于水导电是因为生成H2CO3，CO2本身不能电离，是非电解质。BaSO4是难溶电解质，HCl和NaOH是电解质。"},
{"id": "chem-mc-009", "t": "choice", "q": "下列氧化物中与水反应能生成对应含氧酸的是", "o": ["A. SiO2", "B. SO3", "C. CuO", "D. Al2O3"], "a": "B", "e": "SO3与水反应生成H2SO4。SiO2不溶于水，CuO与水不反应，Al2O3与水不反应。"},
{"id": "chem-mc-010", "t": "choice", "q": "下列属于同素异形体的一组是", "o": ["A. H2O和D2O", "B. O2和O3", "C. CO和CO2", "D. Na和Na+"], "a": "B", "e": "同素异形体是同种元素组成的不同单质。O2和O3都是氧元素的单质。H2O和D2O是同位素化合物，Na+是离子。"},
{"id": "chem-mc-011", "t": "choice", "q": "下列物质属于有机物的是", "o": ["A. CO", "B. CO2", "C. CH4", "D. H2CO3"], "a": "C", "e": "有机物是含碳化合物（CO、CO2、碳酸盐等除外）。CH4甲烷是最简单的有机物。"},
{"id": "chem-mc-012", "t": "choice", "q": "下列物质的分类不正确的是", "o": ["A. Na2O2属于过氧化物", "B. KOH属于强碱", "C. H2SO4属于含氧酸", "D. Na2CO3属于酸式盐"], "a": "D", "e": "Na2CO3是正盐，NaHCO3才是酸式盐。"},
{"id": "chem-mc-013", "t": "choice", "q": "既能与酸反应又能与碱反应的是", "o": ["A. Na2O", "B. Al2O3", "C. SO2", "D. CO2"], "a": "B", "e": "Al2O3是两性氧化物，既与酸反应又与碱反应。Na2O只与酸反应，SO2和CO2只与碱反应。"},
{"id": "chem-mc-014", "t": "choice", "q": "下列物质中属于强电解质的是", "o": ["A. CH3COOH", "B. NH3*H2O", "C. BaSO4", "D. H2CO3"], "a": "C", "e": "BaSO4虽难溶但溶解部分完全电离，属于强电解质。CH3COOH、NH3*H2O、H2CO3是弱电解质。"},
{"id": "chem-mc-015", "t": "choice", "q": "下列关于纯净物的说法正确的是", "o": ["A. 纯净物一定由分子构成", "B. 由同种分子构成的物质一定是纯净物", "C. 纯净物都由同种元素组成", "D. 含有同种元素的物质一定是纯净物"], "a": "B", "e": "由同种分子构成的物质一定是纯净物，这是判断标准。纯净物可由原子或离子构成，不一定由分子构成。"},
{"id": "chem-mc-016", "t": "choice", "q": "下列属于强酸的是", "o": ["A. H2CO3", "B. H2SO3", "C. HClO", "D. HNO3"], "a": "D", "e": "三大强酸是HCl、H2SO4、HNO3。H2CO3是弱酸，H2SO3是中强酸，HClO是弱酸。"},
{"id": "chem-mc-017", "t": "choice", "q": "下列物质的水溶液呈碱性的是", "o": ["A. NaCl", "B. Na2CO3", "C. NH4Cl", "D. KNO3"], "a": "B", "e": "Na2CO3是强碱弱酸盐，CO3^2-水解使溶液呈碱性。NaCl和KNO3呈中性，NH4Cl呈酸性。"},
{"id": "chem-mc-018", "t": "choice", "q": "下列属于复盐的是", "o": ["A. CuSO4*5H2O", "B. KAl(SO4)2*12H2O", "C. FeSO4*7H2O", "D. CaSO4*2H2O"], "a": "B", "e": "复盐含两种以上金属阳离子。明矾KAl(SO4)2*12H2O含K+和Al3+，是复盐。"},
{"id": "chem-mc-019", "t": "choice", "q": "下列关于氧化物的说法正确的是", "o": ["A. 金属氧化物都是碱性氧化物", "B. 非金属氧化物都是酸性氧化物", "C. 碱性氧化物一定能与酸反应生成盐和水", "D. 酸性氧化物都能与水反应生成酸"], "a": "C", "e": "碱性氧化物的定义就是能与酸反应生成盐和水的氧化物，C正确。Mn2O7是金属氧化物但不是碱性氧化物，SiO2是酸性氧化物但不与水反应。"},
{"id": "chem-mc-020", "t": "choice", "q": "下列物质属于弱电解质的是", "o": ["A. NaCl", "B. Ba(OH)2", "C. CH3COOH", "D. H2SO4"], "a": "C", "e": "CH3COOH是弱电解质，在水中部分电离。其他三个都是强电解质。"},
{"id": "chem-mc-021", "t": "choice", "q": "下列物质的用途与化学性质有关的是", "o": ["A. 干冰用于人工降雨", "B. 活性炭用于净水", "C. 氧气用于炼钢", "D. 稀有气体用于霓虹灯"], "a": "C", "e": "氧气炼钢是利用O2的氧化性与杂质反应，属于化学性质。干冰降雨用升华吸热，活性炭用吸附性，霓虹灯用气体放电发光，都是物理性质。"},
{"id": "chem-mc-022", "t": "choice", "q": "下列属于酸式盐的是", "o": ["A. Na2SO4", "B. NaHSO4", "C. Na3PO4", "D. NaCl"], "a": "B", "e": "NaHSO4电离出Na+、H+和SO4^2-，含有可释放的H+，属于酸式盐。"},
{"id": "chem-mc-023", "t": "choice", "q": "下列物质受热分解不属于氧化还原反应的是", "o": ["A. KClO3", "B. KMnO4", "C. CaCO3", "D. H2O2"], "a": "C", "e": "CaCO3分解为CaO和CO2，化合价不变，不是氧化还原反应。其他三个分解都有化合价变化。"},
{"id": "chem-mc-024", "t": "choice", "q": "下列说法不正确的是", "o": ["A. 单质一定由同种元素组成", "B. 由同种元素组成的纯净物一定是单质", "C. 化合物一定由不同种元素组成", "D. 含有多种元素的物质一定是化合物"], "a": "D", "e": "含多种元素的物质也可能是混合物，如空气含N、O等多种元素但是混合物。"},
{"id": "chem-mc-025", "t": "choice", "q": "下列属于共价化合物的是", "o": ["A. NaCl", "B. KBr", "C. HCl", "D. CaO"], "a": "C", "e": "HCl中H和Cl以共价键结合，属于共价化合物。NaCl、KBr、CaO都是离子化合物。"},
{"id": "chem-mc-026", "t": "choice", "q": "下列属于碱性氧化物的是", "o": ["A. Al2O3", "B. Fe2O3", "C. CO2", "D. SiO2"], "a": "B", "e": "Fe2O3是碱性氧化物，能与酸反应。Al2O3是两性氧化物，CO2和SiO2是酸性氧化物。"},
{"id": "chem-mc-027", "t": "choice", "q": "下列物质中含氧酸是", "o": ["A. HCl", "B. H2S", "C. H3PO4", "D. HF"], "a": "C", "e": "含氧酸是含氧原子的酸。H3PO4磷酸含O，是含氧酸。HCl、H2S、HF是无氧酸。"},
{"id": "chem-mc-028", "t": "choice", "q": "下列关于溶液的说法正确的是", "o": ["A. 溶液一定是无色的", "B. 饱和溶液一定比不饱和溶液浓", "C. 溶液是均一稳定的混合物", "D. 溶质只能是固体"], "a": "C", "e": "溶液的特征是均一稳定。溶液可以有色如CuSO4溶液蓝色。"},
{"id": "chem-mc-029", "t": "choice", "q": "下列属于悬浊液的是", "o": ["A. 食盐水", "B. 泥水", "C. 酒精水溶液", "D. 蔗糖水"], "a": "B", "e": "泥水中泥沙是不溶性固体小颗粒悬浮在水中，是悬浊液。其他都是溶液。"},
{"id": "chem-mc-030", "t": "choice", "q": "关于胶体的叙述不正确的是", "o": ["A. 胶体粒子直径在1~100nm", "B. 胶体能发生丁达尔效应", "C. 胶体粒子能透过半透膜", "D. 胶体是较稳定的分散系"], "a": "C", "e": "胶体粒子直径1~100nm，不能透过半透膜（孔径更小）。丁达尔效应是胶体特征。"},
{"id": "chem-mc-031", "t": "choice", "q": "下列化学式书写正确的是", "o": ["A. 碳酸钠NaCO3", "B. 氢氧化钙Ca(OH)2", "C. 氯化铝AlCl2", "D. 硫酸铁FeSO4"], "a": "B", "e": "Ca(OH)2是氢氧化钙正确化学式。A应为Na2CO3，C应为AlCl3，D应为Fe2(SO4)3。"},
{"id": "chem-mc-032", "t": "choice", "q": "下列电离方程式书写正确的是", "o": ["A. NaOH=Na+O+H", "B. H2SO4=H2+ +SO4^2-", "C. CaCl2=Ca2+ +2Cl-", "D. Na2CO3=Na2+ +CO3^2-"], "a": "C", "e": "CaCl2电离为Ca2+和2Cl-。A应为Na++OH-，B应为2H++SO4^2-，D应为2Na++CO3^2-。"},
{"id": "chem-mc-033", "t": "choice", "q": "下列化学方程式配平正确的是", "o": ["A. Al+HCl=AlCl3+H2", "B. 2Al+6HCl=2AlCl3+3H2", "C. Al+3HCl=AlCl3+H2", "D. 3Al+2HCl=3AlCl3+H2"], "a": "B", "e": "2Al+6HCl=2AlCl3+3H2配平正确：Al 0变+3，H +1变0，得失电子守恒。"},
{"id": "chem-mc-034", "t": "choice", "q": "下列反应属于化合反应的是", "o": ["A. 2H2O2=2H2O+O2", "B. CaCO3=CaO+CO2", "C. 2Na+2H2O=2NaOH+H2", "D. 4Fe+3O2=2Fe2O3"], "a": "D", "e": "化合反应是多种物质生成一种物质。4Fe+3O2生成Fe2O3属于化合反应。"},
{"id": "chem-mc-035", "t": "choice", "q": "下列物质的名称与化学式一致的是", "o": ["A. 烧碱Na2CO3", "B. 熟石灰CaO", "C. 石灰石Ca(OH)2", "D. 小苏打NaHCO3"], "a": "D", "e": "小苏打是NaHCO3，D正确。烧碱是NaOH，熟石灰是Ca(OH)2，石灰石是CaCO3。"},
{"id": "chem-mc-036", "t": "choice", "q": "下列化学用语表示的含义正确的是", "o": ["A. 2H表示2个氢分子", "B. H2表示2个氢原子", "C. 2H2表示2个氢分子", "D. H+表示氢原子"], "a": "C", "e": "2H2表示2个氢分子。2H表示2个氢原子，H2表示1个氢分子，H+表示氢离子。"},
{"id": "chem-mc-037", "t": "choice", "q": "下列关于摩尔的说法正确的是", "o": ["A. 摩尔是物质的质量单位", "B. 摩尔是物质的量的单位", "C. 1mol任何物质质量相等", "D. 摩尔是国际单位制导出单位"], "a": "B", "e": "摩尔是物质的量的单位，是七个国际单位制基本单位之一。不是质量单位，1mol不同物质质量不等。"},
{"id": "chem-mc-038", "t": "choice", "q": "下列化合价标注正确的是", "o": ["A. H2O中H为+1价", "B. H2O2中O为-2价", "C. Fe2O3中Fe为+2价", "D. KMnO4中Mn为+6价"], "a": "A", "e": "H2O中H为+1价正确。H2O2中O为-1价，Fe2O3中Fe为+3价，KMnO4中Mn为+7价。"},
{"id": "chem-mc-039", "t": "choice", "q": "下列化学式表示过氧化钠的是", "o": ["A. Na2O", "B. Na2O2", "C. NaOH", "D. NaO2"], "a": "B", "e": "Na2O2是过氧化钠，含过氧键O-O，O为-1价。Na2O是氧化钠。"},
{"id": "chem-mc-040", "t": "choice", "q": "下列属于化学变化的是", "o": ["A. 冰融化", "B. 酒精挥发", "C. 铁生锈", "D. 矿石粉碎"], "a": "C", "e": "铁生锈是铁与氧气和水反应生成铁的氧化物，有新物质生成，属于化学变化。"},
{"id": "chem-mc-041", "t": "choice", "q": "下列表示质量守恒定律的是", "o": ["A. 反应物分子数等于生成物分子数", "B. 反应前后原子种类和数目不变", "C. 反应前后物质种类不变", "D. 反应前后化合价不变"], "a": "B", "e": "质量守恒定律本质是原子种类和数目不变。分子数可以变，物质种类也会变，化合价可能变。"},
{"id": "chem-mc-042", "t": "choice", "q": "下列化学方程式中气体符号使用正确的是", "o": ["A. CaCO3+2HCl=CaCl2+H2O+CO2(气体)", "B. NaOH+HCl=NaCl+H2O(沉淀)", "C. 2H2O2=2H2O+O2(无标记)", "D. BaCl2+Na2SO4=BaSO4(无标记)+2NaCl"], "a": "A", "e": "CaCO3与盐酸反应生成CO2气体需标注气体符号。H2O不是沉淀，O2是气体需标注，BaSO4是沉淀需标注。"},
{"id": "chem-mc-043", "t": "choice", "q": "下列化学式书写不正确的是", "o": ["A. 硫酸铝Al2(SO4)3", "B. 硝酸钙Ca(NO3)2", "C. 氯化铁FeCl2", "D. 碳酸钾K2CO3"], "a": "C", "e": "FeCl2是氯化亚铁，氯化铁应为FeCl3。"},
{"id": "chem-mc-044", "t": "choice", "q": "下列反应既属于氧化还原反应又属于分解反应的是", "o": ["A. CaCO3高温分解", "B. 2KClO3=2KCl+3O2(催化剂加热)", "C. CO2+H2O=H2CO3", "D. HCl+NaOH=NaCl+H2O"], "a": "B", "e": "KClO3分解中Cl从+5变为-1，O从-2变为0，化合价变化，是氧化还原反应也是分解反应。"},
{"id": "chem-mc-045", "t": "choice", "q": "下列分子空间构型为正四面体的是", "o": ["A. H2O", "B. CO2", "C. CH4", "D. NH3"], "a": "C", "e": "CH4是正四面体结构，键角109.5度。H2O是V形，CO2是直线形，NH3是三角锥形。"},
{"id": "chem-mc-046", "t": "choice", "q": "下列化学方程式中不属于氧化还原反应的是", "o": ["A. 2Fe+3Cl2=2FeCl3", "B. Fe2O3+3CO=2Fe+3CO2", "C. CaCO3+2HCl=CaCl2+H2O+CO2", "D. 2H2+O2=2H2O"], "a": "C", "e": "CaCO3与盐酸反应中各元素化合价不变，不是氧化还原反应。"},
{"id": "chem-mc-047", "t": "choice", "q": "下列关于化学用语正确的是", "o": ["A. 1molH2质量是2g", "B. 1molH2O质量是18g/mol", "C. 1molNa质量是23g/mol", "D. 1molCO2质量是44g/mol"], "a": "A", "e": "质量单位是g。1molH2质量=2g/mol*1mol=2g，A正确。B、C、D的单位应为g。"},
{"id": "chem-mc-048", "t": "choice", "q": "下列反应属于置换反应的是", "o": ["A. CaCO3=CaO+CO2", "B. 2Na+2H2O=2NaOH+H2", "C. NaOH+HCl=NaCl+H2O", "D. CaO+H2O=Ca(OH)2"], "a": "B", "e": "置换反应是单质与化合物反应生成新单质和新化合物。2Na+2H2O=2NaOH+H2中Na置换出H2。"},
{"id": "chem-mc-049", "t": "choice", "q": "下列分子式不正确的是", "o": ["A. 乙醇C2H6O", "B. 葡萄糖C6H12O6", "C. 蔗糖C12H22O11", "D. 醋酸C2H3O2"], "a": "D", "e": "醋酸化学式是C2H4O2或CH3COOH，不是C2H3O2。"},
{"id": "chem-mc-050", "t": "choice", "q": "下列关于电子式的说法正确的是", "o": ["A. NaCl电子式为Na+ [:Cl:] -", "B. HCl中只含离子键", "C. NaOH中只含离子键", "D. CO2中含离子键"], "a": "A", "e": "NaCl是离子化合物，电子式为Na+和Cl-。HCl含共价键，NaOH含离子键和共价键，CO2只含共价键。"},
{"id": "chem-mc-051", "t": "choice", "q": "下列物质的俗名与化学式对应正确的是", "o": ["A. 生石灰Ca(OH)2", "B. 熟石灰CaO", "C. 石灰石CaCO3", "D. 纯碱NaOH"], "a": "C", "e": "石灰石主要成分是CaCO3，C正确。生石灰是CaO，熟石灰是Ca(OH)2，纯碱是Na2CO3。"},
{"id": "chem-mc-052", "t": "choice", "q": "下列化学符号中表示两个氧原子的是", "o": ["A. O2", "B. 2O", "C. O^2-", "D. 2O2"], "a": "B", "e": "2O表示两个氧原子。O2表示一个氧分子，O^2-表示氧离子，2O2表示两个氧分子。"},
{"id": "chem-mc-053", "t": "choice", "q": "下列离子方程式书写正确的是", "o": ["A. H++OH-=H2O", "B. Ba2++SO4^2-=BaSO4", "C. A和B都正确", "D. A和B都不正确"], "a": "C", "e": "H++OH-=H2O是强酸强碱中和的离子方程式，Ba2++SO4^2-=BaSO4沉淀的离子方程式，都正确。"},
{"id": "chem-mc-054", "t": "choice", "q": "下列物质中氮元素的化合价为-3的是", "o": ["A. N2", "B. NO", "C. NH3", "D. HNO3"], "a": "C", "e": "NH3中H为+1价，N为-3价。N2中N为0价，NO中N为+2价，HNO3中N为+5价。"},
{"id": "chem-mc-055", "t": "choice", "q": "下列化学计量中属于物质的量的是", "o": ["A. 质量", "B. 体积", "C. 摩尔数", "D. 温度"], "a": "C", "e": "摩尔数就是物质的量。质量、体积、温度都是其他物理量。"},
{"id": "chem-mc-056", "t": "choice", "q": "下列结构式书写正确的是", "o": ["A. 氮气N三N", "B. 乙烯CH2=CH2", "C. 乙炔CH三CH", "D. B和C都正确"], "a": "D", "e": "乙烯含碳碳双键CH2=CH2，乙炔含碳碳三键CH三CH，都正确。氮气含氮氮三键N三N也对。"},
{"id": "chem-mc-057", "t": "choice", "q": "下列关于同位素说法正确的是", "o": ["A. 质子数相同中子数不同的原子", "B. 质量数相同的原子", "C. 电子数相同的原子", "D. 中子数相同的原子"], "a": "A", "e": "同位素是质子数相同中子数不同的核素。如碳-12和碳-14。"},
{"id": "chem-mc-058", "t": "choice", "q": "下列反应中属于吸热反应的是", "o": ["A. 燃烧反应", "B. 中和反应", "C. Ba(OH)2*8H2O与NH4Cl反应", "D. 金属与酸反应"], "a": "C", "e": "Ba(OH)2*8H2O与NH4Cl的反应是著名的吸热反应。燃烧、中和、金属与酸反应都是放热反应。"},
{"id": "chem-mc-059", "t": "choice", "q": "下列化学方程式书写正确的是", "o": ["A. 4P+5O2=2P2O5", "B. 2Mg+O2=2MgO", "C. 2H2+O2=2H2O", "D. 以上都正确"], "a": "D", "e": "三个方程式配平和条件都正确。"},
{"id": "chem-mc-060", "t": "choice", "q": "下列关于分子和原子的说法正确的是", "o": ["A. 分子比原子大", "B. 分子能保持物质的化学性质", "C. 原子是最小的粒子", "D. 分子一定由原子构成"], "a": "B", "e": "分子是保持物质化学性质的最小粒子，B正确。分子不一定比原子大，原子还可再分，分子由原子构成。"},
{"id": "chem-mc-061", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 标准状况下22.4LH2O含NA个分子", "B. 标准状况下22.4LCO2含NA个分子", "C. 标准状况下22.4LSO3含NA个分子", "D. 标准状况下22.4LCCl4含NA个分子"], "a": "B", "e": "标准状况下CO2是气体，22.4L含1mol即NA个分子。H2O标况下是液体，SO3标况下是固体，CCl4标况下是液体。"},
{"id": "chem-mc-062", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molFe与足量稀盐酸反应转移电子数为", "o": ["A. NA", "B. 2NA", "C. 3NA", "D. 6NA"], "a": "B", "e": "Fe与稀盐酸反应生成FeCl2，Fe从0变+2，1molFe转移2mol电子即2NA个。"},
{"id": "chem-mc-063", "t": "choice", "q": "设NA为阿伏加德罗常数的值，标准状况下11.2LN2所含分子数为", "o": ["A. 0.5NA", "B. NA", "C. 2NA", "D. 0.25NA"], "a": "A", "e": "标准状况下11.2LN2的物质的量=11.2/22.4=0.5mol，含0.5NA个分子。"},
{"id": "chem-mc-064", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 1molNa2O2含NA个O2^2-", "B. 1molNa2O2含2NA个O^2-", "C. 1molNa2O2含2NA个Na+", "D. 1molNa2O2含NA个Na+"], "a": "C", "e": "Na2O2中1mol含2molNa+即2NA个。O以O2^2-形式存在，1molNa2O2含1molO2^2-。"},
{"id": "chem-mc-065", "t": "choice", "q": "设NA为阿伏加德罗常数的值，32gO2含有的原子数为", "o": ["A. NA", "B. 2NA", "C. 4NA", "D. 0.5NA"], "a": "B", "e": "32gO2=1mol，含2molO原子即2NA个。"},
{"id": "chem-mc-066", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molH2SO4含有的氧原子数为", "o": ["A. NA", "B. 2NA", "C. 4NA", "D. 6NA"], "a": "C", "e": "1molH2SO4含4molO原子即4NA个。"},
{"id": "chem-mc-067", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 1molD2O含10NA个质子", "B. 1molD2O含10NA个电子", "C. 1molD2O含12NA个中子", "D. 以上都正确"], "a": "D", "e": "D(氘)核内有1质子1中子。1molD2O含10mol质子(8+1+1)、10mol电子、12mol中子(8+2+2)，都对。"},
{"id": "chem-mc-068", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1L1mol/LNaCl溶液含Na+数目为", "o": ["A. NA", "B. 0.5NA", "C. 2NA", "D. 无法确定"], "a": "A", "e": "1L 1mol/L NaCl含1molNa+即NA个。"},
{"id": "chem-mc-069", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 1molSiO2含4NA个Si-O键", "B. 1molSiO2含2NA个Si-O键", "C. 1mol金刚石含2NA个C-C键", "D. 1mol白磷含6NA个P-P键"], "a": "A", "e": "SiO2中每个Si与4个O成键，1molSiO2含4mol Si-O键即4NA个。"},
{"id": "chem-mc-070", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 1molNa与足量O2反应转移2NA个电子", "B. 1molNa与足量O2反应转移NA个电子", "C. 1molNa与O2反应产物一定是Na2O", "D. 1molNa与O2反应产物一定是Na2O2"], "a": "B", "e": "Na无论生成Na2O还是Na2O2，Na都是+1价，1molNa一定转移1mol电子即NA个。"},
{"id": "chem-mc-071", "t": "choice", "q": "设NA为阿伏加德罗常数的值，17gNH3含有的电子数为", "o": ["A. 7NA", "B. 10NA", "C. 17NA", "D. 3NA"], "a": "B", "e": "17gNH3=1mol，N有7个电子，3个H各有1个电子，共10mol电子即10NA个。"},
{"id": "chem-mc-072", "t": "choice", "q": "设NA为阿伏加德罗常数的值，46gNO2所含的分子数为", "o": ["A. NA", "B. 2NA", "C. 0.5NA", "D. 无法确定"], "a": "A", "e": "46gNO2=46/46=1mol，含NA个NO2分子。注意标况下NO2与N2O4存在平衡，但质量确定分子数确定。"},
{"id": "chem-mc-073", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molCH4含有的C-H键数为", "o": ["A. NA", "B. 2NA", "C. 4NA", "D. 5NA"], "a": "C", "e": "1molCH4含4molC-H键即4NA个。"},
{"id": "chem-mc-074", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 28gCO和28gN2所含分子数相同", "B. 28gCO和28gN2所含原子数相同", "C. A和B都正确", "D. A和B都不正确"], "a": "C", "e": "CO和N2摩尔质量都是28g/mol，28g都等于1mol，分子数相同。1分子CO和1分子N2都含2个原子，原子数也相同。"},
{"id": "chem-mc-075", "t": "choice", "q": "设NA为阿伏加德罗常数的值，0.5molH2O含有的原子总数为", "o": ["A. 0.5NA", "B. 1NA", "C. 1.5NA", "D. 2NA"], "a": "C", "e": "0.5molH2O含0.5molO原子和1molH原子，共1.5mol原子即1.5NA个。"},
{"id": "chem-mc-076", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molFeCl3含有的Cl-数目为", "o": ["A. NA", "B. 2NA", "C. 3NA", "D. 6NA"], "a": "C", "e": "1molFeCl3固体中含3molCl-即3NA个。"},
{"id": "chem-mc-077", "t": "choice", "q": "设NA为阿伏加德罗常数的值，标准状况下44.8LCO2的质量为", "o": ["A. 44g", "B. 88g", "C. 22g", "D. 176g"], "a": "B", "e": "标况下44.8LCO2=2mol，质量=2*44=88g。"},
{"id": "chem-mc-078", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 常温常压下22.4LN2含NA个分子", "B. 标准状况下22.4LN2含NA个分子", "C. 1L水中含NA个水分子", "D. 1molH2质量为2g/mol"], "a": "B", "e": "标准状况下22.4LN2=1mol含NA个分子。常温常压下气体摩尔体积不是22.4L/mol，1L水约55.6mol。"},
{"id": "chem-mc-079", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molCu与足量稀HNO3反应转移的电子数为", "o": ["A. NA", "B. 2NA", "C. 3NA", "D. 4NA"], "a": "B", "e": "Cu与稀HNO3反应生成Cu(NO3)2，Cu从0变+2，1molCu转移2mol电子即2NA个。"},
{"id": "chem-mc-080", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. 1mol任何物质都含NA个分子", "B. 1molH2含有NA个氢原子", "C. 1molH2含有2NA个氢原子", "D. 1molH2含有2NA个质子"], "a": "C", "e": "1molH2含2molH原子即2NA个。1mol物质不一定含NA个分子（可能是离子），H2含2mol质子但不是2NA而是2NA。"},
{"id": "chem-mc-081", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molNa2O2与足量水反应转移电子数为", "o": ["A. NA", "B. 2NA", "C. 3NA", "D. 4NA"], "a": "A", "e": "Na2O2+2H2O=4NaOH+O2，O从-1变为0和-2，1molNa2O2中2molO(-1)只有1mol升到0，转移1mol电子即NA个。"},
{"id": "chem-mc-082", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molC2H6含有C-H键的数目为", "o": ["A. NA", "B. 2NA", "C. 6NA", "D. 8NA"], "a": "C", "e": "C2H6中每个C连3个H，共6个C-H键，1molC2H6含6molC-H键即6NA个。"},
{"id": "chem-mc-083", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1L0.1mol/LNa2SO4溶液含Na+数目为", "o": ["A. 0.1NA", "B. 0.2NA", "C. 0.4NA", "D. NA"], "a": "B", "e": "Na2SO4中n(Na+)=2*0.1mol=0.2mol即0.2NA个。"},
{"id": "chem-mc-084", "t": "choice", "q": "设NA为阿伏加德罗常数的值，标准状况下2.24LHCl溶于水，溶液中H+数目为", "o": ["A. 0.1NA", "B. 0.2NA", "C. NA", "D. 2NA"], "a": "A", "e": "标况下2.24LHCl=0.1mol，HCl完全电离产生0.1molH+即0.1NA个。"},
{"id": "chem-mc-085", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列说法正确的是", "o": ["A. NA个H2O的质量为18g", "B. NA个H2的质量为1g", "C. NA个CO2的质量为28g", "D. NA个N2的质量为14g"], "a": "A", "e": "NA个H2O=1mol，质量=18g。NA个H2=1mol质量2g，NA个CO2质量44g，NA个N2质量28g。"},
{"id": "chem-mc-086", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1mol白磷P4含有的共价键数目为", "o": ["A. 4NA", "B. 5NA", "C. 6NA", "D. 8NA"], "a": "C", "e": "P4是正四面体结构，6条棱即6个P-P键，1molP4含6molP-P键即6NA个。"},
{"id": "chem-mc-087", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molNa2O2与CO2完全反应生成O2的分子数为", "o": ["A. 0.25NA", "B. 0.5NA", "C. NA", "D. 2NA"], "a": "B", "e": "2Na2O2+2CO2=2Na2CO3+O2，1molNa2O2生成0.5molO2即0.5NA个分子。"},
{"id": "chem-mc-088", "t": "choice", "q": "设NA为阿伏加德罗常数的值，下列含有的原子数目最多的是", "o": ["A. 0.5molCH4", "B. 0.5molH2O", "C. 0.5molNH3", "D. 0.5molHF"], "a": "A", "e": "0.5molCH4含0.5*5=2.5mol原子，H2O含0.5*3=1.5mol，NH3含0.5*4=2mol，HF含0.5*2=1mol。CH4最多。"},
{"id": "chem-mc-089", "t": "choice", "q": "设NA为阿伏加德罗常数的值，等质量的下列气体含分子数最多的是", "o": ["A. H2", "B. O2", "C. N2", "D. CO2"], "a": "A", "e": "等质量时，摩尔质量越小分子数越多。H2摩尔质量2g/mol最小，分子数最多。"},
{"id": "chem-mc-090", "t": "choice", "q": "设NA为阿伏加德罗常数的值，1molAl与足量NaOH溶液反应转移的电子数为", "o": ["A. NA", "B. 2NA", "C. 3NA", "D. 6NA"], "a": "C", "e": "2Al+2NaOH+2H2O=2NaAlO2+3H2，Al从0变+3，1molAl转移3mol电子即3NA个。"},
{"id": "chem-mc-091", "t": "choice", "q": "下列元素化合价最高的是", "o": ["A. S", "B. Cl", "C. N", "D. P"], "a": "B", "e": "S最高+6，Cl最高+7，N最高+5，P最高+5，Cl最高价最大。"},
{"id": "chem-mc-092", "t": "choice", "q": "下列化合物中Cl元素化合价为+5的是", "o": ["A. NaCl", "B. NaClO", "C. NaClO2", "D. NaClO3"], "a": "D", "e": "NaCl中Cl为-1，NaClO中Cl为+1，NaClO2中Cl为+3，NaClO3中Cl为+5。"},
{"id": "chem-mc-093", "t": "choice", "q": "在K2Cr2O7中Cr元素的化合价为", "o": ["A. +3", "B. +5", "C. +6", "D. +7"], "a": "C", "e": "K为+1，O为-2，设Cr为x，则2+2x+(-2)*7=0，解得x=+6。"},
{"id": "chem-mc-094", "t": "choice", "q": "下列物质中N元素的化合价最低的是", "o": ["A. N2", "B. NO", "C. NH3", "D. HNO3"], "a": "C", "e": "N2为0，NO为+2，NH3中N为-3，HNO3中N为+5。NH3最低。"},
{"id": "chem-mc-095", "t": "choice", "q": "MnO4-中Mn元素的化合价为", "o": ["A. +4", "B. +5", "C. +6", "D. +7"], "a": "D", "e": "O为-2，设Mn为x，则x+(-2)*4=-1，解得x=+7。"},
{"id": "chem-mc-096", "t": "choice", "q": "Na2S2O3中S元素的化合价为", "o": ["A. -2", "B. 0", "C. +2", "D. +6"], "a": "C", "e": "Na为+1，O为-2，设S为x，则2+2x+(-2)*3=0，解得x=+2。注意这里两个S化合价相同。"},
{"id": "chem-mc-097", "t": "choice", "q": "Fe3O4中铁元素的平均化合价为", "o": ["A. +2", "B. +3", "C. +8/3", "D. +4"], "a": "C", "e": "O为-2，设Fe平均为x，则3x+(-2)*4=0，解得x=+8/3。实际上Fe3O4中Fe有+2和+3两种价态。"},
{"id": "chem-mc-098", "t": "choice", "q": "下列关于化合价的说法正确的是", "o": ["A. 金属元素一定显正价", "B. 非金属元素一定显负价", "C. 单质中元素化合价为0", "D. 化合价只能为整数"], "a": "C", "e": "单质中元素化合价为0。金属不一定显正价（如NaH中H为-1），非金属可以显正价（如SO3中S为+6），化合价也可以是分数。"},
{"id": "chem-mc-099", "t": "choice", "q": "下列反应中CO2是氧化剂的是", "o": ["A. CO2+H2O=H2CO3", "B. CO2+C=2CO(高温)", "C. CO2+2NaOH=Na2CO3+H2O", "D. 2CO2+2Na2O2=2Na2CO3+O2"], "a": "B", "e": "CO2+C=2CO中C从0变+2被氧化（作还原剂），CO2中C从+4变+2被还原（作氧化剂）。"},
{"id": "chem-mc-100", "t": "choice", "q": "在反应MnO2+4HCl(浓)=MnCl2+Cl2+2H2O中，氧化剂是", "o": ["A. MnO2", "B. HCl", "C. MnCl2", "D. Cl2"], "a": "A", "e": "MnO2中Mn从+4降到+2，被还原，MnO2是氧化剂。HCl中Cl从-1升到0，被氧化，HCl是还原剂。"},
{"id": "chem-mc-101", "t": "choice", "q": "下列物质中只具有还原性的是", "o": ["A. Cl2", "B. FeCl3", "C. FeCl2", "D. KMnO4"], "a": "C", "e": "FeCl2中Fe为+2，可以升高到+3，只能被氧化，只具有还原性。Cl2既可氧化也可还原，FeCl3可被还原，KMnO4可被还原。"},
{"id": "chem-mc-102", "t": "choice", "q": "下列物质中既可作氧化剂又可作还原剂的是", "o": ["A. KMnO4", "B. H2", "C. SO2", "D. Na2O2"], "a": "C", "e": "SO2中S为+4，可降到+2或0（作氧化剂），也可升到+6（作还原剂）。H2只能被氧化，KMnO4只能被还原，Na2O2只能被还原。"},
{"id": "chem-mc-103", "t": "choice", "q": "在反应2Fe3++Cu=2Fe2++Cu2+中，氧化剂是", "o": ["A. Fe3+", "B. Cu", "C. Fe2+", "D. Cu2+"], "a": "A", "e": "Fe3+被还原为Fe2+，Fe3+是氧化剂。Cu被氧化为Cu2+，Cu是还原剂。"},
{"id": "chem-mc-104", "t": "choice", "q": "实验室制取Cl2的反应中，浓盐酸表现的性质是", "o": ["A. 只表现酸性", "B. 只表现还原性", "C. 既表现酸性又表现还原性", "D. 既表现氧化性又表现酸性"], "a": "C", "e": "4molHCl参加反应，其中2mol被氧化为Cl2（还原性），2mol生成MnCl2（酸性）。浓盐酸既表现还原性又表现酸性。"},
{"id": "chem-mc-105", "t": "choice", "q": "下列反应属于氧化还原反应的是", "o": ["A. CaCO3+2HCl=CaCl2+H2O+CO2", "B. 2H2O2=2H2O+O2", "C. BaCl2+Na2SO4=BaSO4+2NaCl", "D. NaOH+HCl=NaCl+H2O"], "a": "B", "e": "H2O2分解中O从-1分别变为-2和0，化合价有升降，属于氧化还原反应。其余反应无化合价变化。"},
{"id": "chem-mc-106", "t": "choice", "q": "下列反应中，水既作氧化剂又作还原剂的是", "o": ["A. 2Na+2H2O=2NaOH+H2", "B. 2H2O2=2H2O+O2", "C. C+H2O=CO+H2(高温)", "D. CaO+H2O=Ca(OH)2"], "a": "C", "e": "C+H2O=CO+H2中，水中O从-2升到+2（被氧化，水作还原剂），水中H从+1降到0（被还原，水作氧化剂），所以水既作氧化剂又作还原剂。"},
{"id": "chem-mc-107", "t": "choice", "q": "将铁片放入下列溶液中，铁片质量增加的是", "o": ["A. FeCl3溶液", "B. CuSO4溶液", "C. 稀H2SO4", "D. MgSO4溶液"], "a": "B", "e": "Fe与CuSO4反应：Fe+CuSO4=FeSO4+Cu，溶解56gFe置换出64gCu，铁片质量增加。Fe与FeCl3和H2SO4反应质量减少，Fe与MgSO4不反应。"},
{"id": "chem-mc-108", "t": "choice", "q": "下列反应中，每摩尔反应物参加反应转移电子数最多的是", "o": ["A. Cu+2H2SO4(浓)=CuSO4+SO2+2H2O", "B. 2Fe+3Cl2=2FeCl3", "C. MnO2+4HCl(浓)=MnCl2+Cl2+2H2O", "D. C+2H2SO4(浓)=CO2+2SO2+2H2O"], "a": "D", "e": "D中C从0到+4转移4e-，2molH2SO4中2molS从+6到+4共转移4e-，每摩尔C转移4e-最多。A转移2e-，B中每molCl2转移2e-，C转移2e-。"},
{"id": "chem-mc-109", "t": "choice", "q": "在反应2KMnO4+16HCl(浓)=2KCl+2MnCl2+5Cl2+8H2O中，被氧化的HCl与参加反应的HCl的物质的量之比为", "o": ["A. 1:8", "B. 5:8", "C. 5:16", "D. 10:16"], "a": "B", "e": "16molHCl参加反应，其中10mol被氧化生成5molCl2（还原性），6mol作酸性介质生成KCl和MnCl2。被氧化的占10/16=5/8。10:16=5:8。答案是B。"},
{"id": "chem-mc-110", "t": "choice", "q": "下列关于氧化还原反应的说法正确的是", "o": ["A. 氧化剂得到电子", "B. 氧化还原反应一定有电子转移", "C. 反应中所有元素化合价都发生变化", "D. 氧化还原反应一定有氧气参加"], "a": "B", "e": "氧化还原反应的本质是有电子转移（或电子对偏移），标志是化合价升降。氧化剂得到电子被还原，但不是所有元素化合价都变化，也不一定有氧气参加。"},
{"id": "chem-mc-111", "t": "choice", "q": "强氧化剂KMnO4与浓盐酸反应时，若生成0.5molCl2，则转移的电子数为", "o": ["A. 0.5mol", "B. 1mol", "C. 2mol", "D. 4mol"], "a": "B", "e": "2Cl-→Cl2+2e-，生成1molCl2转移2mol电子，0.5molCl2转移1mol电子。"},
{"id": "chem-mc-112", "t": "choice", "q": "下列反应不属于氧化还原反应的是", "o": ["A. 2Na2O2+2H2O=4NaOH+O2", "B. 2F2+2H2O=4HF+O2", "C. 3NO2+H2O=2HNO3+NO", "D. SO2+H2O=H2SO3"], "a": "D", "e": "SO2+H2O=H2SO3中各元素化合价不变，不是氧化还原反应。其余反应都有化合价变化。"},
{"id": "chem-mc-113", "t": "choice", "q": "已知反应2A-+B2=2B-+A2，则氧化性由强到弱的顺序是", "o": ["A. A2>B2>A->B-", "B. B2>A2>B->A-", "C. A->B->A2>B2", "D. B->A->B2>A2"], "a": "B", "e": "氧化剂氧化性>氧化产物，B2是氧化剂，A2是氧化产物，所以B2>A2。还原剂还原性>还原产物，A-是还原剂，B-是还原产物，所以A->B-。"},
{"id": "chem-mc-114", "t": "choice", "q": "在铜与浓硝酸反应中，氧化剂与还原剂的物质的量之比为", "o": ["A. 4:1", "B. 2:1", "C. 1:2", "D. 1:1"], "a": "B", "e": "Cu+4HNO3(浓)=Cu(NO3)2+2NO2+2H2O，4molHNO3中2mol被还原为NO2（氧化剂），Cu为还原剂。氧化剂:还原剂=2:1。"},
{"id": "chem-mc-115", "t": "choice", "q": "下列物质在空气中久置会变质且发生氧化还原反应的是", "o": ["A. NaOH", "B. Na2O2", "C. Na2SO3", "D. NaCl"], "a": "C", "e": "Na2SO3在空气中与O2反应生成Na2SO4：2Na2SO3+O2=2Na2SO4，S从+4升到+6，O从0降到-2，是氧化还原反应。NaOH吸收CO2不是氧化还原，Na2O2与CO2反应生成O2但Na2O2本身是氧化剂和还原剂，NaCl不变质。"},
{"id": "chem-mc-116", "t": "choice", "q": "下列反应中H2O2只作还原剂的是", "o": ["A. 2H2O2=2H2O+O2", "B. H2O2+2KI+2HCl=2KCl+I2+2H2O", "C. H2O2+Cl2=2HCl+O2", "D. H2O2+Na2SO3=Na2SO4+H2O"], "a": "C", "e": "H2O2+Cl2=2HCl+O2中H2O2的O从-1升到0（被氧化，作还原剂），Cl2被还原为HCl。H2O2只作还原剂。"},
{"id": "chem-mc-117", "t": "choice", "q": "下列关于H2O2的说法错误的是", "o": ["A. H2O2既有氧化性又有还原性", "B. H2O2分解是氧化还原反应", "C. H2O2中O的化合价为-2", "D. H2O2可做漂白剂"], "a": "C", "e": "H2O2中O的化合价为-1，不是-2。H2O2中O为-1价，可升到0（还原性）也可降到-2（氧化性），分解反应是氧化还原反应，可做漂白剂。"},
{"id": "chem-mc-118", "t": "choice", "q": "NO2溶于水反应3NO2+H2O=2HNO3+NO中，氧化剂与还原剂的物质的量之比为", "o": ["A. 1:1", "B. 1:2", "C. 2:1", "D. 3:1"], "a": "B", "e": "3NO2中，2个N从+4变+5被氧化（还原剂），1个N从+4变+2被还原（氧化剂）。氧化剂:还原剂=1:2。"},
{"id": "chem-mc-119", "t": "choice", "q": "下列各组物质反应，不能产生H2的是", "o": ["A. Zn+稀H2SO4", "B. Al+NaOH溶液", "C. Cu+稀HCl", "D. Fe+稀H2SO4"], "a": "C", "e": "Cu排在H后面，不能与稀HCl反应产生H2。Zn、Al、Fe都能与稀H2SO4反应产生H2，Al还能与NaOH溶液反应产生H2。"},
{"id": "chem-mc-120", "t": "choice", "q": "下列说法正确的是", "o": ["A. 氧化剂在反应中得到电子", "B. 氧化剂在反应中化合价升高", "C. 还原反应是失去电子的过程", "D. 氧化还原反应中氧化剂和还原剂一定是不同的物质"], "a": "A", "e": "氧化剂得到电子，化合价降低，被还原。还原剂失去电子，化合价升高，被氧化。氧化剂和还原剂可以是同一物质（如Cl2+H2O歧化反应）。"},
{"id": "chem-mc-121", "t": "choice", "q": "根据反应判断，下列微粒氧化性最强的是：2Fe3++2I-=2Fe2++I2，Cl2+2Fe2+=2Cl-+2Fe3+", "o": ["A. Fe3+", "B. I2", "C. Cl2", "D. Cl-"], "a": "C", "e": "由第二个反应知Cl2>Fe3+（氧化剂>氧化产物），由第一个反应知Fe3+>I2。所以Cl2>Fe3+>I2，Cl2氧化性最强。"},
{"id": "chem-mc-122", "t": "choice", "q": "往FeCl3溶液中加入适量铜粉，反应后溶液中一定存在的阳离子是", "o": ["A. Fe3+", "B. Cu2+", "C. Fe2+", "D. Fe2+和Cu2+"], "a": "D", "e": "2Fe3++Cu=2Fe2++Cu2+，反应后生成Fe2+和Cu2+。若铜粉适量，Fe3+恰好完全反应，则溶液中有Fe2+和Cu2+。"},
{"id": "chem-mc-123", "t": "choice", "q": "在反应Br2+2NaOH=NaBr+NaBrO+H2O中，Br2发生的反应是", "o": ["A. 只被氧化", "B. 只被还原", "C. 既被氧化又被还原", "D. 未被氧化未被还原"], "a": "C", "e": "Br2中Br为0价，反应后一部分变为-1（NaBr中被还原），一部分变为+1（NaBrO中被氧化），Br2既被氧化又被还原，属于歧化反应。"},
{"id": "chem-mc-124", "t": "choice", "q": "下列物质长期暴露在空气中，不会因氧化还原反应而变质的是", "o": ["A. Na2SO3溶液", "B. KI溶液", "C. NaOH溶液", "D. H2S溶液"], "a": "C", "e": "NaOH吸收CO2变为Na2CO3，是复分解反应不是氧化还原。Na2SO3被O2氧化为Na2SO4，KI被O2氧化为I2，H2S被O2氧化为S，都是氧化还原反应变质。"},
{"id": "chem-mc-125", "t": "choice", "q": "等质量的下列金属与足量稀盐酸反应，产生H2最多的是", "o": ["A. Na", "B. Mg", "C. Al", "D. Fe"], "a": "C", "e": "等质量m，产生H2=（m/M）*（化合价/2）*2。设m=1g：Na(23)产1/23mol，Mg(24)产1/12mol，Al(27)产1/9mol(=0.111)，Fe(56)产1/28mol。Al产H2最多，因为当质量相同时，M/化合价最小的产H2最多，Al的M/化合价=27/3=9最小。"},
{"id": "chem-mc-126", "t": "choice", "q": "下列金属与足量稀硫酸反应，产生等量H2时，消耗金属质量最少的是", "o": ["A. Na", "B. Mg", "C. Al", "D. Fe"], "a": "C", "e": "产生1molH2：需Na 46g(2Na→H2)，Mg 24g，Al 18g(2Al→3H2即产生1molH2需18g)，Fe 56g。Al最少。"},
{"id": "chem-mc-127", "t": "choice", "q": "将SO2通入溴水中，溶液褪色，体现了SO2的", "o": ["A. 氧化性", "B. 还原性", "C. 漂白性", "D. 酸性"], "a": "B", "e": "SO2+Br2+2H2O=H2SO4+2HBr，SO2中S从+4升到+6被氧化，SO2作还原剂，体现还原性。虽然SO2也有漂白性，但这里是与溴水反应褪色，不是漂白。"},
{"id": "chem-mc-128", "t": "choice", "q": "下列关于钠的说法正确的是", "o": ["A. 钠在空气中燃烧生成Na2O", "B. 钠保存在煤油中", "C. 钠是银白色较硬的金属", "D. 钠可以保存在水中"], "a": "B", "e": "钠是活泼金属，保存在煤油中以隔绝空气和水。钠燃烧生成Na2O2而非Na2O，钠质地较软可用刀切，钠与水剧烈反应不能保存在水中。"},
{"id": "chem-mc-129", "t": "choice", "q": "钠在空气中燃烧的产物是", "o": ["A. Na2O", "B. Na2O2", "C. NaOH", "D. Na2CO3"], "a": "B", "e": "钠在空气中燃烧发出黄色火焰，生成淡黄色Na2O2。常温下钠在空气中缓慢氧化生成Na2O。"},
{"id": "chem-mc-130", "t": "choice", "q": "将少量钠投入水中，不能观察到的现象是", "o": ["A. 钠浮在水面上", "B. 钠熔成银白色小球", "C. 有气泡产生", "D. 溶液变红色"], "a": "D", "e": "钠与水反应生成NaOH和H2，但题目未说明水中加酚酞，溶液不一定变红。钠浮在水面（密度小于水）、熔成小球（反应放热、熔点低）、有气泡（H2）都可以观察到。"},
{"id": "chem-mc-131", "t": "choice", "q": "Na2O2与水反应的产物是", "o": ["A. NaOH和O2", "B. NaOH和H2", "C. Na2O和O2", "D. NaOH和H2O2"], "a": "A", "e": "2Na2O2+2H2O=4NaOH+O2，Na2O2与水反应生成NaOH和O2。"},
{"id": "chem-mc-132", "t": "choice", "q": "下列关于Na2O2的说法正确的是", "o": ["A. Na2O2是碱性氧化物", "B. Na2O2与水反应是氧化还原反应", "C. Na2O2与CO2反应不产生O2", "D. Na2O2中O为-2价"], "a": "B", "e": "2Na2O2+2H2O=4NaOH+O2，O的化合价从-1分别变为-2和0，有化合价变化是氧化还原反应。Na2O2不是碱性氧化物（反应生成O2），与CO2反应产生O2，O化合价为-1。"},
{"id": "chem-mc-133", "t": "choice", "q": "Na2O2可用于呼吸面具和潜水艇中，原因是", "o": ["A. Na2O2能产生NaOH供人呼吸", "B. Na2O2能吸收CO2并产生O2", "C. Na2O2能吸收O2", "D. Na2O2能产生H2O供人使用"], "a": "B", "e": "2Na2O2+2CO2=2Na2CO3+O2，Na2O2既能吸收CO2又能产生O2，适合用于呼吸面具。"},
{"id": "chem-mc-134", "t": "choice", "q": "下列关于Na2CO3和NaHCO3的说法正确的是", "o": ["A. Na2CO3比NaHCO3易溶于水", "B. NaHCO3热稳定性比Na2CO3强", "C. 二者都能与NaOH反应", "D. Na2CO3能与盐酸反应产生CO2，NaHCO3不能"], "a": "A", "e": "Na2CO3溶解度大于NaHCO3。NaHCO3受热分解但Na2CO3不分解。Na2CO3不能与NaOH反应，NaHCO3能与NaOH反应。两者都能与盐酸反应产生CO2。"},
{"id": "chem-mc-135", "t": "choice", "q": "除去Na2CO3中少量NaHCO3的方法是", "o": ["A. 加盐酸", "B. 加热", "C. 加NaOH溶液", "D. 通入CO2"], "a": "B", "e": "2NaHCO3=Na2CO3+H2O+CO2（加热），加热使NaHCO3分解为Na2CO3，除去了NaHCO3且不引入新杂质。"},
{"id": "chem-mc-136", "t": "choice", "q": "向Na2CO3溶液中滴加少量盐酸，反应的离子方程式为", "o": ["A. CO3^2-+2H+=CO2+H2O", "B. CO3^2-+H+=HCO3-", "C. HCO3-+H+=CO2+H2O", "D. CO3^2-+H2O=HCO3-+OH-"], "a": "B", "e": "向Na2CO3溶液中滴加少量盐酸时，盐酸不足，CO3^2-先转化为HCO3-：CO3^2-+H+=HCO3-。只有盐酸过量时才会继续产生CO2。"},
{"id": "chem-mc-137", "t": "choice", "q": "相同温度下，下列溶液pH最大的是", "o": ["A. 0.1mol/LNaCl", "B. 0.1mol/LNaHCO3", "C. 0.1mol/LNa2CO3", "D. 0.1mol/LNaOH"], "a": "D", "e": "NaOH是强碱，pH最大。Na2CO3水解呈碱性但不如NaOH强，NaHCO3水解程度较小，NaCl中性。"},
{"id": "chem-mc-138", "t": "choice", "q": "焰色试验是利用某些元素的什么性质来鉴别的", "o": ["A. 元素的放射性", "B. 元素原子发射光谱的特征颜色", "C. 元素的化合价", "D. 元素的密度"], "a": "B", "e": "焰色试验是某些金属或其化合物在灼烧时使火焰呈现特殊颜色，利用的是元素原子发射光谱的特征。Na为黄色，K为紫色（透过蓝色钴玻璃）。"},
{"id": "chem-mc-139", "t": "choice", "q": "下列关于碱金属的说法正确的是", "o": ["A. 碱金属单质都能保存在空气中", "B. 碱金属的熔点从Li到Cs逐渐降低", "C. 碱金属的密度从Li到Cs逐渐减小", "D. Li的还原性最强"], "a": "B", "e": "碱金属从Li到Cs金属性增强，熔沸点逐渐降低，密度总体增大（Li<K<Na<Rb<Cs但Na>K）。碱金属都要隔绝空气保存，Cs还原性最强。"},
{"id": "chem-mc-140", "t": "choice", "q": "Na与水反应的现象不能说明钠具有的性质是", "o": ["A. 钠的密度小于水", "B. 钠的熔点低", "C. 钠的还原性强", "D. 钠是银白色"], "a": "D", "e": "钠浮在水面（密度小于水），熔成小球（熔点低，反应放热），剧烈反应（还原性强）。银白色是钠本身的颜色，与水反应不能说明这一点（反应前就能看到）。"},
{"id": "chem-mc-141", "t": "choice", "q": "铝在常温下能被浓硝酸钝化，说明铝具有", "o": ["A. 酸性", "B. 碱性", "C. 金属性和非金属性", "D. 两性"], "a": "D", "e": "Al既能与酸反应又能与碱反应，是两性金属。钝化是强氧化性酸使表面形成致密氧化膜。"},
{"id": "chem-mc-142", "t": "choice", "q": "下列关于氧化铝的说法正确的是", "o": ["A. Al2O3是典型的碱性氧化物", "B. Al2O3是典型的酸性氧化物", "C. Al2O3是两性氧化物", "D. Al2O3不能与酸反应"], "a": "C", "e": "Al2O3既能与强酸反应又能与强碱反应，是两性氧化物。Al2O3+6HCl=2AlCl3+3H2O，Al2O3+2NaOH=2NaAlO2+H2O。"},
{"id": "chem-mc-143", "t": "choice", "q": "氧化铝和氢氧化铝的共同性质是", "o": ["A. 都能溶于水", "B. 都既能溶于强酸又能溶于强碱", "C. 都是白色固体", "D. 都能与弱酸弱碱反应"], "a": "B", "e": "Al2O3和Al(OH)3都是两性的，既能溶于强酸又能溶于强碱。Al(OH)3是白色胶状沉淀不溶于水，Al2O3也不溶于水，两者只与强酸强碱反应。"},
{"id": "chem-mc-144", "t": "choice", "q": "下列关于Al(OH)3的说法错误的是", "o": ["A. Al(OH)3是两性氢氧化物", "B. Al(OH)3不溶于氨水", "C. Al(OH)3受热易分解", "D. Al(OH)3能溶于弱酸"], "a": "D", "e": "Al(OH)3是两性氢氧化物，但不溶于弱酸（如碳酸）和弱碱（如氨水）。只溶于强酸和强碱。Al(OH)3受热分解为Al2O3和H2O。"},
{"id": "chem-mc-145", "t": "choice", "q": "要使AlCl3溶液中的Al3+完全沉淀，最佳试剂是", "o": ["A. NaOH溶液", "B. 氨水", "C. KOH溶液", "D. Ba(OH)2溶液"], "a": "B", "e": "用氨水使Al3+完全沉淀为Al(OH)3，Al(OH)3不溶于过量氨水。用NaOH等强碱过量时Al(OH)3会溶解。"},
{"id": "chem-mc-146", "t": "choice", "q": "向AlCl3溶液中逐渐加入NaOH溶液，下列图像正确的是", "o": ["A. 沉淀量先增后减至零", "B. 沉淀量一直增大", "C. 沉淀量先增大后不变", "D. 无沉淀生成"], "a": "A", "e": "Al3++3OH-=Al(OH)3（沉淀增多），Al(OH)3+OH-=AlO2-+2H2O（沉淀溶解）。NaOH过量时沉淀完全溶解。"},
{"id": "chem-mc-147", "t": "choice", "q": "向NaOH溶液中逐渐加入AlCl3溶液，正确描述现象的是", "o": ["A. 开始有沉淀，后沉淀增多", "B. 开始无沉淀，后有沉淀，再沉淀增多", "C. 一直有沉淀", "D. 始终无沉淀"], "a": "B", "e": "NaOH过量时Al3++4OH-=AlO2-+2H2O（无沉淀），继续加AlCl3至NaOH消耗完后，Al3++3AlO2-+6H2O=4Al(OH)3（产生沉淀）。"},
{"id": "chem-mc-148", "t": "choice", "q": "铝热反应常用于焊接铁轨，反应为Al+Fe2O3=Al2O3+2Fe，该反应中铝的作用是", "o": ["A. 催化剂", "B. 氧化剂", "C. 还原剂", "D. 既不是氧化剂也不是还原剂"], "a": "C", "e": "铝热反应中Al从0升到+3被氧化，作还原剂。Fe2O3中Fe从+3降到0被还原，作氧化剂。"},
{"id": "chem-mc-149", "t": "choice", "q": "下列物质可用于做耐火材料的是", "o": ["A. Al2O3", "B. Na2O", "C. MgCl2", "D. CuO"], "a": "A", "e": "Al2O3熔点很高（2050度），可做耐火材料（坩埚等）。天然氧化铝（刚玉）硬度也很大。"},
{"id": "chem-mc-150", "t": "choice", "q": "明矾[KAl(SO4)2*12H2O]常用于净水，其原理是", "o": ["A. 明矾能消毒杀菌", "B. Al3+水解产生Al(OH)3胶体吸附杂质", "C. 明矾能与杂质反应", "D. 明矾能产生Cl2消毒"], "a": "B", "e": "明矾溶于水后Al3+水解：Al3++3H2O=Al(OH)3(胶体)+3H+，Al(OH)3胶体表面积大，能吸附水中悬浮杂质使之沉降。"},
{"id": "chem-mc-151", "t": "choice", "q": "下列离子在水中能大量共存的是", "o": ["A. Al3+、OH-、Na+、Cl-", "B. Al3+、HCO3-、Na+、Cl-", "C. Al3+、NH4+、Cl-、NO3-", "D. AlO2-、H+、Na+、Cl-"], "a": "C", "e": "Al3+和OH-生成Al(OH)3沉淀，Al3+和HCO3-发生双水解反应（Al3++3HCO3-=Al(OH)3+3CO2），AlO2-和H+生成Al(OH)3。只有C组离子能大量共存。"},
{"id": "chem-mc-152", "t": "choice", "q": "从海水中提取镁的正确步骤是", "o": ["A. 海水直接电解得镁", "B. 海水加石灰乳得Mg(OH)2，再加盐酸得MgCl2，电解熔融MgCl2", "C. 海水加NaOH得Mg(OH)2直接加热分解", "D. 海水加石灰乳得Mg(OH)2直接电解"], "a": "B", "e": "海水→加Ca(OH)2得Mg(OH)2沉淀→过滤→加盐酸得MgCl2溶液→蒸发浓缩→电解熔融MgCl2得Mg和Cl2。这是工业上从海水中提取镁的流程。"},
{"id": "chem-mc-153", "t": "choice", "q": "下列关于铁的说法正确的是", "o": ["A. 铁是黑色金属", "B. 纯铁是银白色金属", "C. 铁在常温下不能与非氧化性酸反应", "D. 铁不能被磁铁吸引"], "a": "B", "e": "纯铁是银白色金属，铁能被磁铁吸引，铁能与稀H2SO4、盐酸等非氧化性酸反应。铁在纯氧中燃烧生成Fe3O4，在潮湿空气中生锈（Fe2O3*xH2O）。"},
{"id": "chem-mc-154", "t": "choice", "q": "铁与足量稀硝酸反应的产物是", "o": ["A. Fe(NO3)2和H2", "B. Fe(NO3)3和H2", "C. Fe(NO3)3和NO", "D. Fe(NO3)3、NO和H2"], "a": "C", "e": "稀HNO3有强氧化性，Fe+4HNO3(稀)=Fe(NO3)3+NO+2H2O，生成Fe(NO3)3和NO，不生成H2。"},
{"id": "chem-mc-155", "t": "choice", "q": "铁与少量Cl2反应的产物是", "o": ["A. FeCl2", "B. FeCl3", "C. Fe和FeCl3", "D. Fe3O4"], "a": "B", "e": "铁与Cl2反应直接生成FeCl3，因为Cl2氧化性强：2Fe+3Cl2=2FeCl3。铁与弱氧化剂（如S、HCl）反应生成FeCl2。"},
{"id": "chem-mc-156", "t": "choice", "q": "铁在纯氧中燃烧的产物是", "o": ["A. FeO", "B. Fe2O3", "C. Fe3O4", "D. FeO和Fe2O3"], "a": "C", "e": "铁在纯氧中燃烧：3Fe+2O2=Fe3O4，生成黑色Fe3O4。"},
{"id": "chem-mc-157", "t": "choice", "q": "下列物质中，与铁反应能生成Fe3+的是", "o": ["A. 稀盐酸", "B. CuSO4溶液", "C. 氯气", "D. 硫粉"], "a": "C", "e": "Cl2氧化性强，与铁直接生成Fe3+。稀H2SO4和CuSO4溶液与铁反应生成Fe2+，S粉与铁反应生成FeS（Fe2+）。"},
{"id": "chem-mc-158", "t": "choice", "q": "Fe(OH)2在空气中放置会迅速变色，最终变为", "o": ["A. 白色", "B. 灰绿色", "C. 红褐色", "D. 黑色"], "a": "C", "e": "白色Fe(OH)2在空气中迅速被氧化：Fe(OH)2→灰绿色（中间产物）→红褐色Fe(OH)3。"},
{"id": "chem-mc-159", "t": "choice", "q": "实验室制备Fe(OH)2时应注意的关键操作是", "o": ["A. 使用热水", "B. 将吸有NaOH溶液的长胶管插入FeSO4液面下", "C. 加入催化剂", "D. 加热反应"], "a": "B", "e": "Fe(OH)2极易被氧化，制备时需将NaOH溶液长胶管插入FeSO4液面下（隔绝空气），且FeSO4溶液最好新制并用煮沸过的蒸馏水配制。"},
{"id": "chem-mc-160", "t": "choice", "q": "检验Fe3+的最佳试剂是", "o": ["A. NaOH溶液", "B. KSCN溶液", "C. 石蕊溶液", "D. 酚酞溶液"], "a": "B", "e": "Fe3+遇到KSCN溶液变血红色，灵敏度高。NaOH溶液生成红褐色沉淀也能检验但不如KSCN灵敏。"},
{"id": "chem-mc-161", "t": "choice", "q": "向含Fe3+和Fe2+的混合溶液中加入KSCN溶液，现象是", "o": ["A. 溶液变血红色", "B. 溶液不变色", "C. 产生白色沉淀", "D. 产生气泡"], "a": "A", "e": "KSCN只与Fe3+反应变血红色，与Fe2+不反应。混合溶液中有Fe3+，所以溶液变血红色。"},
{"id": "chem-mc-162", "t": "choice", "q": "下列关于FeCl3溶液的说法正确的是", "o": ["A. 溶液呈中性", "B. 加入铁粉后溶液颜色变浅", "C. 遇KSCN不变色", "D. 能与Cu反应生成Fe2+"], "a": "D", "e": "2Fe3++Cu=2Fe2++Cu2+，FeCl3能与Cu反应。FeCl3溶液因Fe3+水解呈酸性。加入铁粉Fe+2Fe3+=3Fe2+，溶液颜色变浅（黄色变浅绿色）。Fe3+遇KSCN变血红色。"},
{"id": "chem-mc-163", "t": "choice", "q": "下列物质不能由化合反应得到的是", "o": ["A. FeCl3", "B. FeS", "C. FeCl2", "D. NaCl"], "a": "C", "e": "2Fe+3Cl2=2FeCl3（化合反应），Fe+S=FeS（化合反应），2Na+Cl2=2NaCl（化合反应）。FeCl2不能由化合反应得到（Fe与Cl2直接反应得Fe3+，Fe与HCl反应不是化合反应）。"},
{"id": "chem-mc-164", "t": "choice", "q": "下列关于铜的说法正确的是", "o": ["A. 铜在常温下能与稀硫酸反应", "B. 铜在潮湿空气中生锈生成铜绿", "C. 铜是不活泼金属，不能被氧化", "D. 铜不能与非金属反应"], "a": "B", "e": "铜在潮湿空气中生成铜绿Cu2(OH)2CO3。铜不能与稀H2SO4反应（排在H后面），但能与热的浓H2SO4、HNO3等氧化性酸反应。铜在加热下能与O2、Cl2等非金属反应。"},
{"id": "chem-mc-165", "t": "choice", "q": "铜与稀硝酸反应的化学方程式为", "o": ["A. Cu+4HNO3(稀)=Cu(NO3)2+2NO2+2H2O", "B. 3Cu+8HNO3(稀)=3Cu(NO3)2+2NO+4H2O", "C. Cu+2HNO3(稀)=Cu(NO3)2+H2", "D. Cu+HNO3(稀)=CuO+NO2+H2O"], "a": "B", "e": "铜与稀硝酸反应生成NO而非NO2：3Cu+8HNO3(稀)=3Cu(NO3)2+2NO+4H2O。铜与浓硝酸才生成NO2。"},
{"id": "chem-mc-166", "t": "choice", "q": "下列溶液呈蓝色的是", "o": ["A. FeCl3溶液", "B. CuSO4溶液", "C. NaCl溶液", "D. KMnO4溶液"], "a": "B", "e": "CuSO4溶液中Cu2+水合离子呈蓝色。FeCl3溶液呈黄色，NaCl无色，KMnO4呈紫红色。"},
{"id": "chem-mc-167", "t": "choice", "q": "铜与浓硫酸反应时，还原剂与氧化剂的物质的量之比为", "o": ["A. 1:1", "B. 1:2", "C. 2:1", "D. 1:4"], "a": "A", "e": "Cu+2H2SO4(浓)=CuSO4+SO2+2H2O，Cu（还原剂）与被还原的H2SO4（氧化剂，1mol）之比为1:1。注意2molH2SO4中只有1mol被还原。"},
{"id": "chem-mc-168", "t": "choice", "q": "下列关于合金的说法正确的是", "o": ["A. 合金一定是金属与金属熔合而成", "B. 合金的熔点一般比成分金属低", "C. 合金中只含金属元素", "D. 合金的硬度一般比成分金属低"], "a": "B", "e": "合金的熔点一般低于组成它的纯金属，硬度一般高于成分金属。合金可以是金属与金属或金属与非金属的混合物，如钢（Fe-C合金）含非金属C。"},
{"id": "chem-mc-169", "t": "choice", "q": "下列关于铜的化合物说法正确的是", "o": ["A. CuO是黑色固体，Cu2O是红色固体", "B. CuO和Cu2O都是黑色的", "C. CuO是红色的，Cu2O是黑色的", "D. Cu(OH)2是蓝色溶液"], "a": "A", "e": "CuO是黑色粉末，Cu2O是红色粉末。Cu(OH)2是蓝色固体（不溶），CuSO4*5H2O是蓝色晶体。"},
{"id": "chem-mc-170", "t": "choice", "q": "下列关于碳元素的说法正确的是", "o": ["A. 金刚石和石墨互为同位素", "B. 金刚石和石墨互为同素异形体", "C. 金刚石和石墨化学性质相同", "D. 碳只有金刚石和石墨两种单质"], "a": "B", "e": "金刚石和石墨都是碳元素的单质，互为同素异形体（同种元素不同单质）。它们物理性质不同（硬度、导电性等），化学性质相似但有差异。C60也是碳的一种单质。"},
{"id": "chem-mc-171", "t": "choice", "q": "下列物质中硬度最大的是", "o": ["A. 金刚石", "B. 石墨", "C. 晶体硅", "D. 石英"], "a": "A", "e": "金刚石是天然物质中硬度最大的，因为其正四面体网状结构中C-C键非常牢固。"},
{"id": "chem-mc-172", "t": "choice", "q": "石墨能导电的原因是", "o": ["A. 石墨含有自由电子", "B. 石墨中碳原子间有自由移动的电子", "C. 石墨是金属", "D. 石墨含有金属离子"], "a": "B", "e": "石墨是层状结构，每个C原子形成3个C-C键，剩下1个电子可以在层间自由移动，所以石墨能导电。"},
{"id": "chem-mc-173", "t": "choice", "q": "CO和CO2的比较，下列说法正确的是", "o": ["A. 都是有毒气体", "B. 都能使澄清石灰水变浑浊", "C. 都能与水反应", "D. 都是碳的氧化物"], "a": "D", "e": "CO和CO2都是碳的氧化物。CO有毒而CO2无毒（但高浓度CO2也窒息），只有CO2能使石灰水变浑浊，CO不溶于水，CO2能与水反应。"},
{"id": "chem-mc-174", "t": "choice", "q": "下列关于CO的说法正确的是", "o": ["A. CO是酸性氧化物", "B. CO能使人中毒", "C. CO能被NaOH吸收", "D. CO能在空气中安静燃烧发出蓝色火焰"], "a": "B", "e": "CO有毒，能与血红蛋白结合导致中毒。CO不是酸性氧化物，不能被NaOH吸收。CO在空气中燃烧发出蓝色火焰。"},
{"id": "chem-mc-175", "t": "choice", "q": "下列关于CO2的说法错误的是", "o": ["A. CO2是酸性氧化物", "B. CO2能使石蕊试液变红", "C. CO2有毒", "D. 固态CO2俗称干冰"], "a": "C", "e": "CO2无毒（但高浓度导致窒息），不是有毒气体。CO2是酸性氧化物，溶于水生成碳酸使石蕊变红，固态CO2叫干冰可用于人工降雨。"},
{"id": "chem-mc-176", "t": "choice", "q": "下列反应中CO作还原剂的是", "o": ["A. CO2+H2O=H2CO3", "B. CO2+C=2CO", "C. CO+CuO=Cu+CO2", "D. 2NaOH+CO2=Na2CO3+H2O"], "a": "C", "e": "CO+CuO=Cu+CO2中CO从+2升到+4被氧化，作还原剂。CuO从+2降到0被还原。"},
{"id": "chem-mc-177", "t": "choice", "q": "下列关于SiO2的说法正确的是", "o": ["A. SiO2是酸性氧化物，能与水反应生成硅酸", "B. SiO2能与NaOH溶液反应", "C. SiO2不溶于任何酸", "D. SiO2是气态物质"], "a": "B", "e": "SiO2是酸性氧化物但不溶于水。SiO2+2NaOH=Na2SiO3+H2O，能与强碱反应。SiO2能与氢氟酸反应：SiO2+4HF=SiF4+2H2O。SiO2是固态。"},
{"id": "chem-mc-178", "t": "choice", "q": "下列材料属于硅酸盐产品的是", "o": ["A. 塑料", "B. 水泥", "C. 橡胶", "D. 玻璃纤维"], "a": "B", "e": "传统三大硅酸盐产品是水泥、玻璃、陶瓷。水泥主要成分是硅酸钙。"},
{"id": "chem-mc-179", "t": "choice", "q": "制造光导纤维的主要原料是", "o": ["A. 石英(SiO2)", "B. 晶体硅", "C. 碳酸钠", "D. 碳酸钙"], "a": "A", "e": "光导纤维的主要成分是SiO2（石英玻璃）。高纯度SiO2制成的光纤传输光信号，损耗极低。"},
{"id": "chem-mc-180", "t": "choice", "q": "下列关于硅的说法正确的是", "o": ["A. 晶体硅是良好的导体", "B. 硅是地壳中含量最多的元素", "C. 硅的化学性质不活泼", "D. 硅可用于制造半导体芯片"], "a": "D", "e": "硅是半导体材料，广泛用于制造芯片和太阳能电池。晶体硅不是良好导体（是半导体），地壳中含量最多的是O（48.6%），硅是第二（26.3%）。硅化学性质较稳定。"},
{"id": "chem-mc-181", "t": "choice", "q": "下列试剂能区分Na2CO3和NaHCO3固体的是", "o": ["A. 水", "B. 加热", "C. BaCl2溶液", "D. 以上都可以"], "a": "B", "e": "加热法最直接：NaHCO3受热分解产生CO2使石灰水变浑浊，Na2CO3不分解。Na2CO3溶解度更大但两者都溶于水，BaCl2都能产生沉淀。"},
{"id": "chem-mc-182", "t": "choice", "q": "用CO还原CuO的实验中，下列操作正确的是", "o": ["A. 先加热再通CO", "B. 先通CO排尽空气再加热", "C. 反应结束后先停止通CO再停止加热", "D. 不需要尾气处理"], "a": "B", "e": "必须先通CO排尽装置内空气再加热，防止CO与空气混合加热爆炸。反应结束后先停止加热，继续通CO直到冷却，防止Cu被重新氧化。尾气CO有毒需处理。"},
{"id": "chem-mc-183", "t": "choice", "q": "下列关于氯气的说法正确的是", "o": ["A. 氯气是黄绿色有毒气体", "B. 氯气无色无味", "C. 氯气是液态", "D. 氯气无毒"], "a": "A", "e": "氯气是黄绿色有刺激性气味的有毒气体。液氯是液态氯单质。"},
{"id": "chem-mc-184", "t": "choice", "q": "下列关于氯水的说法正确的是", "o": ["A. 新制氯水只含Cl2分子", "B. 新制氯水中含有HClO", "C. 氯水久置后成分不变", "D. 氯水不能使有色布条褪色"], "a": "B", "e": "新制氯水含Cl2、HClO、H+、Cl-、H2O等。HClO有漂白性可使有色布条褪色。久置后HClO分解，氯水变为稀盐酸。"},
{"id": "chem-mc-185", "t": "choice", "q": "新制氯水具有的性质不包括", "o": ["A. 酸性", "B. 漂白性", "C. 氧化性", "D. 还原性"], "a": "D", "e": "新制氯水含HClO（漂白、氧化）、HCl（酸性）、Cl2（氧化），主要表现氧化性而非还原性。"},
{"id": "chem-mc-186", "t": "choice", "q": "下列物质中氯元素化合价最高的是", "o": ["A. Cl2", "B. HClO", "C. HClO4", "D. NaCl"], "a": "C", "e": "Cl2中Cl为0，HClO中Cl为+1，HClO4中Cl为+7，NaCl中Cl为-1。高氯酸HClO4中Cl化合价最高。"},
{"id": "chem-mc-187", "t": "choice", "q": "实验室制取Cl2的离子方程式为", "o": ["A. MnO2+4HCl=MnCl2+Cl2+2H2O", "B. MnO2+4H++2Cl-=Mn2++Cl2+2H2O", "C. 2KMnO4+16HCl=2KCl+2MnCl2+5Cl2+8H2O", "D. MnO2+2H++2Cl-=Mn2++Cl2+H2O"], "a": "B", "e": "MnO2+4HCl(浓)=MnCl2+Cl2+2H2O，离子方程式为MnO2+4H++2Cl-=Mn2++Cl2+2H2O。注意浓盐酸中HCl完全电离。"},
{"id": "chem-mc-188", "t": "choice", "q": "下列关于漂白粉的说法正确的是", "o": ["A. 漂白粉有效成分是NaClO", "B. 漂白粉有效成分是Ca(ClO)2", "C. 漂白粉是纯净物", "D. 漂白粉在干燥空气中稳定"], "a": "B", "e": "漂白粉是Ca(ClO)2和CaCl2的混合物，有效成分是Ca(ClO)2。漂白粉在空气中吸收CO2和H2O生成HClO而失效。"},
{"id": "chem-mc-189", "t": "choice", "q": "漂白粉在空气中失效的原因用方程式表示正确的是", "o": ["A. Ca(ClO)2+CO2+H2O=CaCO3+2HClO", "B. 2HClO=2HCl+O2", "C. Ca(ClO)2+2HCl=CaCl2+2HClO", "D. A和B两个反应共同导致"], "a": "D", "e": "漂白粉在空气中先与CO2和H2O反应：Ca(ClO)2+CO2+H2O=CaCO3+2HClO，然后HClO见光分解：2HClO=2HCl+O2。两个反应共同导致漂白粉失效。"},
{"id": "chem-mc-190", "t": "choice", "q": "下列物质具有漂白性的是", "o": ["A. SO2", "B. Cl2", "C. Na2O2", "D. 以上都有"], "a": "D", "e": "SO2与有色物质结合生成不稳定的无色化合物（可逆），Cl2溶于水生成HClO漂白，Na2O2与水反应生成O2和NaOH也有漂白性。三者都有漂白性但原理不同。"},
{"id": "chem-mc-191", "t": "choice", "q": "下列关于次氯酸的说法正确的是", "o": ["A. HClO是强酸", "B. HClO不稳定，见光易分解", "C. HClO没有氧化性", "D. HClO没有漂白性"], "a": "B", "e": "HClO是弱酸（比H2CO3还弱），见光分解为HCl和O2：2HClO=2HCl+O2。HClO有强氧化性和漂白性，是氯水漂白消毒的有效成分。"},
{"id": "chem-mc-192", "t": "choice", "q": "下列实验能用同一原理解释的是", "o": ["A. SO2和Cl2都能使品红溶液褪色", "B. SO2和Na2O2都能使品红溶液褪色", "C. 活性炭和SO2都能使红墨水褪色", "D. HClO和O3都能使有色物质褪色"], "a": "D", "e": "HClO和O3都是因强氧化性使有色物质褪色。SO2是化合漂白（可逆），活性炭是物理吸附。SO2和Cl2虽然都能使品红褪色但原理不同。"},
{"id": "chem-mc-193", "t": "choice", "q": "检验Cl-的方法是", "o": ["A. 加AgNO3溶液有白色沉淀即可确认", "B. 加AgNO3溶液有白色沉淀，再加稀HNO3沉淀不溶", "C. 加稀HNO酸化后再加AgNO3溶液", "D. 加BaCl2溶液看有无沉淀"], "a": "B", "e": "加AgNO3生成白色沉淀后加稀HNO3沉淀不溶，才能确认Cl-。CO3^2-、SO3^2-等也生成白色Ag沉淀但溶于稀HNO3。不先加HNO3酸化会引入杂质。"},
{"id": "chem-mc-194", "t": "choice", "q": "下列氯化物中不能用金属与稀盐酸直接反应制取的是", "o": ["A. FeCl2", "B. MgCl2", "C. AlCl3", "D. FeCl3"], "a": "D", "e": "铁与稀盐酸反应生成FeCl2（铁为+2价），不能直接得到FeCl3。FeCl3需用铁与氯气反应或由FeCl2氧化得到。"},
{"id": "chem-mc-195", "t": "choice", "q": "下列关于硫的说法正确的是", "o": ["A. 硫是黄色固体，不溶于水", "B. 硫是黑色固体", "C. 硫是气体", "D. 硫能溶于水"], "a": "A", "e": "硫是淡黄色固体，不溶于水，微溶于酒精，易溶于CS2。"},
{"id": "chem-mc-196", "t": "choice", "q": "硫与铁反应的产物是", "o": ["A. FeS2", "B. FeS", "C. Fe2S3", "D. FeSO4"], "a": "B", "e": "Fe+S=FeS，硫的氧化性弱，只能将Fe氧化到+2价。Cl2与铁反应得到FeCl3。"},
{"id": "chem-mc-197", "t": "choice", "q": "下列气体中能用NaOH固体干燥的是", "o": ["A. SO2", "B. HCl", "C. CO2", "D. 以上都不能"], "a": "D", "e": "SO2、HCl、CO2都是酸性气体，都能与NaOH反应，不能用NaOH固体干燥。NaOH固体只能干燥碱性或中性气体如NH3、H2、O2、N2等。"},
{"id": "chem-mc-198", "t": "choice", "q": "下列关于SO2的说法正确的是", "o": ["A. SO2是有毒气体", "B. SO2是酸性氧化物", "C. SO2能被O2氧化为SO3", "D. 以上都正确"], "a": "D", "e": "SO2是无色有刺激性气味的有毒气体，是酸性氧化物（SO2+H2O=H2SO3），能被催化氧化为SO3：2SO2+O2=2SO3（催化剂加热）。"},
{"id": "chem-mc-199", "t": "choice", "q": "SO2的漂白原理是", "o": ["A. SO2具有强氧化性", "B. SO2与有色物质化合生成不稳定的无色化合物", "C. SO2能吸附有色物质", "D. SO2分解有色物质"], "a": "B", "e": "SO2的漂白是化合漂白，与有色物质结合生成不稳定的无色化合物，加热后分解恢复原色。这与HClO的氧化漂白不同。"},
{"id": "chem-mc-200", "t": "choice", "q": "下列关于硫酸的说法正确的是", "o": ["A. 稀硫酸有强氧化性", "B. 浓硫酸有强氧化性", "C. 浓硫酸能干燥SO2", "D. 浓硫酸能干燥H2S"], "a": "B", "e": "浓硫酸有强氧化性（S从+6降到+4或0等），稀硫酸氧化性来自H+较弱。浓硫酸能干燥SO2（不与SO2反应），但不能干燥H2S（氧化还原反应）。"},
{"id": "chem-mc-201", "t": "choice", "q": "浓硫酸的特性不包括", "o": ["A. 吸水性", "B. 脱水性", "C. 强氧化性", "D. 强还原性"], "a": "D", "e": "浓硫酸三大特性：吸水性（做干燥剂）、脱水性（使有机物碳化）、强氧化性（与Cu等反应）。浓硫酸是强氧化剂，不是还原剂。"},
{"id": "chem-mc-202", "t": "choice", "q": "蔗糖中加入浓硫酸会变黑，体现了浓硫酸的", "o": ["A. 吸水性", "B. 脱水性", "C. 强氧化性", "D. 酸性"], "a": "B", "e": "蔗糖（C12H22O11）被浓硫酸脱水碳化变黑：C12H22O11=12C+11H2O，体现脱水性。同时C被浓硫酸氧化产生SO2等气体。"},
{"id": "chem-mc-203", "t": "choice", "q": "铜与浓硫酸反应时，体现浓硫酸的性质是", "o": ["A. 只有酸性", "B. 只有强氧化性", "C. 酸性和强氧化性", "D. 脱水性"], "a": "C", "e": "Cu+2H2SO4(浓)=CuSO4+SO2+2H2O，H2SO4中S从+6降到+4体现强氧化性，部分H2SO4生成CuSO4体现酸性。"},
{"id": "chem-mc-204", "t": "choice", "q": "下列关于SO3的说法正确的是", "o": ["A. SO3是气体", "B. SO3是固态", "C. SO3与水反应生成H2SO3", "D. SO3不能与NaOH反应"], "a": "B", "e": "SO3在常温下是无色固体，标准状况下也是固体。SO3+H2O=H2SO4（不是H2SO3）。SO3+2NaOH=Na2SO4+H2O。"},
{"id": "chem-mc-205", "t": "choice", "q": "下列关于H2S的说法正确的是", "o": ["A. H2S是无色无味气体", "B. H2S有臭鸡蛋气味", "C. H2S能被浓H2SO4干燥", "D. H2S能燃烧只能生成SO2"], "a": "B", "e": "H2S是无色有臭鸡蛋气味的剧毒气体。不能被浓H2SO4干燥（被氧化）。H2S在O2不足时燃烧生成S，O2充足时生成SO2。"},
{"id": "chem-mc-206", "t": "choice", "q": "浓硫酸稀释的正确操作是", "o": ["A. 将水倒入浓硫酸中", "B. 将浓硫酸沿容器壁缓缓加入水中，并用玻璃棒搅拌", "C. 将浓硫酸快速倒入水中", "D. 任意顺序都可以"], "a": "B", "e": "浓硫酸稀释时放出大量热，必须将浓硫酸沿容器壁缓缓注入水中，并用玻璃棒不断搅拌散热。若将水倒入浓硫酸中，水沸腾飞溅会导致危险。"},
{"id": "chem-mc-207", "t": "choice", "q": "下列气体中能用浓硫酸干燥的是", "o": ["A. NH3", "B. H2S", "C. HI", "D. SO2"], "a": "D", "e": "浓硫酸不能干燥NH3（反应）、H2S（氧化）、HI（氧化）等还原性气体。SO2虽是还原性气体但浓硫酸不能氧化SO2（S已达最高价+6），所以可以干燥SO2。"},
{"id": "chem-mc-208", "t": "choice", "q": "下列关于硫化氢在氧气中燃烧的说法正确的是", "o": ["A. 完全燃烧生成SO2", "B. 不完全燃烧生成SO2", "C. 完全燃烧生成S", "D. 不完全燃烧生成SO3"], "a": "A", "e": "2H2S+3O2=2SO2+2H2O（完全燃烧），2H2S+O2=2S+2H2O（不完全燃烧，O2不足时）。"},
{"id": "chem-mc-209", "t": "choice", "q": "浓硫酸与铜反应需加热，说明该反应", "o": ["A. 是吸热反应", "B. 反应速率慢，加热加快反应", "C. 是放热反应", "D. 无法判断"], "a": "B", "e": "浓硫酸与铜的反应是放热反应，但需要加热来加快反应速率，使反应持续进行。加热不改变反应是吸热还是放热。"},
{"id": "chem-mc-210", "t": "choice", "q": "氮气的化学性质不活泼的原因是", "o": ["A. 氮原子半径大", "B. N三键键能大，断裂困难", "C. 氮气是惰性气体", "D. 氮原子核外电子多"], "a": "B", "e": "氮气分子中N三键键能很大（946kJ/mol），断裂需要很高的能量，所以N2化学性质稳定。"},
{"id": "chem-mc-211", "t": "choice", "q": "氮的固定是指", "o": ["A. 将游离态氮转化为化合态氮", "B. 将化合态氮转化为游离态氮", "C. 氮气液化", "D. 氮气溶于水"], "a": "A", "e": "氮的固定是将空气中游离态的N2转化为含氮化合物（化合态氮）的过程，包括自然固氮（闪电、豆科植物根瘤菌）和人工固氮（合成氨）。"},
{"id": "chem-mc-212", "t": "choice", "q": "下列属于自然固氮的是", "o": ["A. 工业合成氨", "B. 闪电时N2与O2反应生成NO", "C. 氮气与氢气在催化剂下反应", "D. 用硝酸制炸药"], "a": "B", "e": "闪电时高温高压下N2+O2=2NO，是自然固氮。工业合成氨是人工固氮。"},
{"id": "chem-mc-213", "t": "choice", "q": "NO的化学性质正确的是", "o": ["A. NO是无色无味气体", "B. NO能与O2反应生成NO2", "C. NO是红棕色气体", "D. NO能溶于水"], "a": "B", "e": "NO是无色气体，在空气中迅速与O2反应：2NO+O2=2NO2。NO2才是红棕色气体。NO不溶于水。"},
{"id": "chem-mc-214", "t": "choice", "q": "NO2是红棕色气体，溶于水反应的化学方程式为", "o": ["A. 3NO2+H2O=2HNO3+NO", "B. NO2+H2O=HNO3+HNO2", "C. 2NO2+H2O=HNO3+NO", "D. NO2+H2O=HNO3"], "a": "A", "e": "3NO2+H2O=2HNO3+NO，NO2溶于水生成HNO3和NO（无色气体）。"},
{"id": "chem-mc-215", "t": "choice", "q": "下列关于氮的氧化物的说法正确的是", "o": ["A. 所有氮的氧化物都是红棕色", "B. NO和NO2都是大气污染物", "C. N2O5是白色固体", "D. 氮的氧化物都能溶于水"], "a": "B", "e": "NO是无色气体，NO2是红棕色。NO和NO2都能导致光化学烟雾和酸雨，是大气污染物。N2O5是无色固体。NO不溶于水。"},
{"id": "chem-mc-216", "t": "choice", "q": "下列关于氨气(NH3)的说法正确的是", "o": ["A. NH3是无色无味气体", "B. NH3极易溶于水", "C. NH3水溶液呈酸性", "D. NH3是三角锥形结构"], "a": "B", "e": "NH3是无色有刺激性气味的气体，极易溶于水（1体积水溶解700体积NH3），水溶液呈碱性。NH3是三角锥形结构，N上有孤电子对。"},
{"id": "chem-mc-217", "t": "choice", "q": "氨气溶于水呈碱性的原因是", "o": ["A. NH3本身是碱", "B. NH3与水反应生成NH3*H2O，NH3*H2O部分电离产生OH-", "C. NH3电离产生OH-", "D. 水电离被促进"], "a": "B", "e": "NH3+H2O=NH3*H2O=NH4++OH-，NH3与水结合生成NH3*H2O（一水合氨），NH3*H2O部分电离出OH-，使溶液呈碱性。NH3本身不是碱。"},
{"id": "chem-mc-218", "t": "choice", "q": "氨气的喷泉实验说明了氨气具有的性质是", "o": ["A. 氨气有还原性", "B. 氨气极易溶于水且水溶液呈碱性", "C. 氨气是碱性气体", "D. 氨气密度比空气大"], "a": "B", "e": "喷泉实验中NH3迅速溶于水使烧瓶内压强急剧减小，外界大气压将水压入烧瓶形成喷泉。酚酞变红说明水溶液呈碱性。"},
{"id": "chem-mc-219", "t": "choice", "q": "下列关于铵盐的说法正确的是", "o": ["A. 铵盐都是固体，都溶于水", "B. 铵盐受热都分解产生NH3", "C. 铵盐与碱反应都能产生NH3", "D. 以上都正确"], "a": "D", "e": "铵盐都是白色固体，都溶于水。铵盐受热易分解（NH4Cl=NH3+HCl），与碱反应产生NH3（NH4Cl+NaOH=NaCl+NH3+H2O）。"},
{"id": "chem-mc-220", "t": "choice", "q": "实验室制取NH3的最佳方法是", "o": ["A. 加热NH4Cl", "B. NH4Cl与Ca(OH)2固体共热", "C. 加热氨水", "D. N2与H2反应"], "a": "B", "e": "2NH4Cl+Ca(OH)2=CaCl2+2NH3+2H2O（加热），这是实验室制备NH3的标准方法。用固体反应可避免水的干扰。"},
{"id": "chem-mc-221", "t": "choice", "q": "下列干燥剂不能用于干燥NH3的是", "o": ["A. 碱石灰", "B. NaOH固体", "C. 浓硫酸", "D. CaO"], "a": "C", "e": "NH3是碱性气体，不能用酸性干燥剂。浓硫酸是酸性干燥剂，会与NH3反应生成铵盐。碱石灰、NaOH固体、CaO都是碱性干燥剂，可以干燥NH3。"},
{"id": "chem-mc-222", "t": "choice", "q": "铵态氮肥使用时不能与碱性物质混合使用，原因是", "o": ["A. 会产生有毒气体", "B. 会降低肥效", "C. 会发生爆炸", "D. 会产生O2"], "a": "B", "e": "铵盐与碱反应生成NH3气体逸出，降低氮肥的肥效。如(NH4)2SO4+2NaOH=Na2SO4+2NH3+2H2O。"},
{"id": "chem-mc-223", "t": "choice", "q": "下列关于HNO3的说法正确的是", "o": ["A. 纯HNO3是无色液体", "B. 浓HNO3是无色液体", "C. HNO3不稳定，见光分解", "D. 以上都正确"], "a": "D", "e": "纯HNO3和浓HNO3都是无色液体（久置因分解产生的NO2溶于其中而变黄）。HNO3不稳定：4HNO3=4NO2+O2+2H2O（见光或加热）。"},
{"id": "chem-mc-224", "t": "choice", "q": "浓硝酸和稀硝酸共有的性质是", "o": ["A. 强氧化性", "B. 能与铜反应", "C. 见光分解", "D. 能使铁钝化"], "a": "A", "e": "浓稀HNO3都有强氧化性。但产物不同：浓HNO3一般还原为NO2，稀HNO3还原为NO。都能与铜反应。铁在浓HNO3中钝化，稀HNO3中不钝化。"},
{"id": "chem-mc-225", "t": "choice", "q": "铜分别与浓硝酸和稀硝酸反应，相同点是", "o": ["A. 都生成NO2", "B. 都生成NO", "C. 都生成Cu(NO3)2", "D. 都有H2生成"], "a": "C", "e": "浓硝酸：Cu+4HNO3=Cu(NO3)2+2NO2+2H2O；稀硝酸：3Cu+8HNO3=3Cu(NO3)2+2NO+4H2O。都生成Cu(NO3)2，但还原产物不同，都不生成H2。"},
{"id": "chem-mc-226", "t": "choice", "q": "常温下，下列金属能用浓硝酸钝化的是", "o": ["A. Cu", "B. Al", "C. Zn", "D. Mg"], "a": "B", "e": "常温下Fe和Al能用浓硝酸和浓硫酸钝化。Cu、Zn、Mg不能钝化，能与浓硝酸反应。"},
{"id": "chem-mc-227", "t": "choice", "q": "浓硝酸发黄的原因是", "o": ["A. 含有Fe3+", "B. 溶有分解产生的NO2", "C. 含有S杂质", "D. 含有Cl-"], "a": "B", "e": "浓硝酸见光或受热分解：4HNO3=4NO2+O2+2H2O，生成的NO2溶于硝酸中使其呈黄色。"},
{"id": "chem-mc-228", "t": "choice", "q": "碳与浓硝酸反应的还原产物是", "o": ["A. NO", "B. NO2", "C. N2", "D. NH3"], "a": "B", "e": "C+4HNO3(浓)=CO2+4NO2+2H2O，碳与浓硝酸反应生成NO2。浓硝酸与金属、非金属反应一般都生成NO2。"},
{"id": "chem-mc-229", "t": "choice", "q": "下列关于硝酸的保存说法正确的是", "o": ["A. 保存在棕色瓶中", "B. 保存在无色玻璃瓶中", "C. 保存在铁罐中", "D. 敞口保存"], "a": "A", "e": "硝酸见光分解，应保存在棕色试剂瓶中，放置在阴凉处。不能用铁罐（铁不钝化会反应），不能敞口保存。"},
{"id": "chem-mc-230", "t": "choice", "q": "下列关于王水的说法正确的是", "o": ["A. 王水是浓硝酸和浓盐酸按体积比3:1混合", "B. 王水是浓硝酸和浓盐酸按体积比1:3混合", "C. 王水能溶解所有金属", "D. 王水不能溶解金和铂"], "a": "B", "e": "王水是浓HNO3和浓HCl按体积比1:3混合，具有极强的氧化性，能溶解Au和Pt等不活泼金属。"},
{"id": "chem-mc-231", "t": "choice", "q": "下列反应中HNO3既表现氧化性又表现酸性的是", "o": ["A. Cu+4HNO3(浓)=Cu(NO3)2+2NO2+2H2O", "B. C+4HNO3(浓)=CO2+4NO2+2H2O", "C. 3Cu+8HNO3(稀)=3Cu(NO3)2+2NO+4H2O", "D. Fe(OH)3+3HNO3=Fe(NO3)3+3H2O"], "a": "A", "e": "A中HNO3一部分生成NO2（氧化性），一部分生成Cu(NO3)2（酸性）。C中也有两部分作用。B中HNO3只表现氧化性，D中只表现酸性。"},
{"id": "chem-mc-232", "t": "choice", "q": "将Cu片分别加入浓HNO3和稀HNO3中，反应现象不同的是", "o": ["A. 溶液都变蓝色", "B. 浓HNO3反应比稀HNO3快", "C. 浓HNO3产生NO2，稀HNO3产生NO", "D. B和C都是"], "a": "D", "e": "浓HNO3与Cu反应速度快，产生红棕色NO2气体。稀HNO3反应慢，产生无色NO气体（在管口变红棕色）。两者都生成蓝色Cu(NO3)2溶液。"},
{"id": "chem-mc-233", "t": "choice", "q": "工业上制HNO3的尾气处理方法是", "o": ["A. 直接排放", "B. 用NaOH溶液吸收", "C. 用水吸收", "D. 燃烧"], "a": "B", "e": "尾气含NO和NO2，用NaOH溶液吸收：NO+NO2+2NaOH=2NaNO2+H2O。不能直接排放（污染大气），单独用水不能完全吸收NO。"},
{"id": "chem-mc-234", "t": "choice", "q": "元素周期表中第三周期元素原子序数从11到18，其中原子半径最小的是", "o": ["A. Na", "B. Ar", "C. Cl", "D. S"], "a": "C", "e": "同周期从左到右原子半径逐渐减小（核电荷数增加），但稀有气体原子半径测定方式不同（范德华半径较大）。所以第三周期中Cl的共价半径最小。若题目排除稀有气体则Cl最小。"},
{"id": "chem-mc-235", "t": "choice", "q": "下列原子半径大小顺序正确的是", "o": ["A. Na<Mg<Al", "B. Li>Na>K", "C. O<S<Se", "D. F>Cl>Br"], "a": "C", "e": "同主族从上到下原子半径增大（Li<Na<K），同周期从左到右减小（Na>Mg>Al）。O<S<Se是同主族从上到下，正确。F<Cl<Br。"},
{"id": "chem-mc-236", "t": "choice", "q": "同主族元素从上到下性质变化的规律正确的是", "o": ["A. 原子半径逐渐减小", "B. 金属性逐渐减弱", "C. 非金属性逐渐减弱", "D. 最高正价逐渐升高"], "a": "C", "e": "同主族从上到下：原子半径增大，金属性增强，非金属性减弱，最外层电子数相同（最高正价相同）。"},
{"id": "chem-mc-237", "t": "choice", "q": "下列元素中金属性最强的是", "o": ["A. Na", "B. Mg", "C. Al", "D. K"], "a": "D", "e": "同周期从左到右金属性减弱（Na>Mg>Al），同主族从上到下金属性增强（Na<K），所以K的金属性最强。"},
{"id": "chem-mc-238", "t": "choice", "q": "下列元素中非金属性最强的是", "o": ["A. F", "B. Cl", "C. O", "D. N"], "a": "A", "e": "F是非金属性最强的元素。同周期从左到右非金属性增强（N<O<F），同主族从上到下非金属性减弱（F>Cl）。"},
{"id": "chem-mc-239", "t": "choice", "q": "下列递变规律正确的是", "o": ["A. 同周期元素最高正价从+1到+7依次增大", "B. 同周期元素原子半径从左到右增大", "C. 同主族元素最高正价相同", "D. 非金属性最强的元素在第七周期"], "a": "C", "e": "同主族元素最外层电子数相同，最高正价相同。同周期最高正价从+1到+7（第IA到VIIA族），但稀有气体一般不讨论正价。原子半径从左到右减小。"},
{"id": "chem-mc-240", "t": "choice", "q": "下列关于碱金属的递变规律说法正确的是", "o": ["A. 从Li到Cs金属性逐渐增强", "B. 从Li到Cs密度逐渐减小", "C. 从Li到Cs熔沸点逐渐升高", "D. 从Li到Cs单质还原性逐渐减弱"], "a": "A", "e": "碱金属从Li到Cs金属性增强，密度总体增大（Na>K反常），熔沸点逐渐降低，还原性逐渐增强。"},
{"id": "chem-mc-241", "t": "choice", "q": "下列关于卤族元素的递变规律说法正确的是", "o": ["A. 从F到I颜色逐渐加深", "B. 从F到I氢化物稳定性逐渐增强", "C. 从F到I单质氧化性逐渐增强", "D. 从F到I原子半径逐渐减小"], "a": "A", "e": "卤素单质颜色：F2（淡黄绿色）<Cl2（黄绿色）<Br2（红棕色）<I2（紫黑色）。氢化物稳定性减弱（HF>HCl>HBr>HI），单质氧化性减弱，原子半径增大。"},
{"id": "chem-mc-242", "t": "choice", "q": "下列氢化物最稳定的是", "o": ["A. HF", "B. HCl", "C. HBr", "D. HI"], "a": "A", "e": "非金属性越强，氢化物越稳定。F非金属性最强，HF最稳定（HF加热到1000度才分解）。"},
{"id": "chem-mc-243", "t": "choice", "q": "下列最高价氧化物对应水化物酸性最强的是", "o": ["A. H2SO4", "B. HClO4", "C. HNO3", "D. H3PO4"], "a": "B", "e": "非金属性越强，最高价含氧酸酸性越强。Cl>S>N>P，所以HClO4（高氯酸）酸性最强。"},
{"id": "chem-mc-244", "t": "choice", "q": "下列最高价氧化物对应水化物碱性最强的是", "o": ["A. NaOH", "B. KOH", "C. Mg(OH)2", "D. Ca(OH)2"], "a": "B", "e": "金属性越强，最高价氧化物对应水化物碱性越强。K>Na>Mg>Ca（碱性KOH>NaOH>Ca(OH)2>Mg(OH)2）。"},
{"id": "chem-mc-245", "t": "choice", "q": "元素周期表中，某元素原子最外层有2个电子，该元素", "o": ["A. 一定是金属元素", "B. 一定是第IIA族元素", "C. 可能是He", "D. 一定是非金属元素"], "a": "C", "e": "最外层2个电子的可能是He（稀有气体，最外层2个已达稳定结构）或第IIA族金属元素（Be、Mg等）。"},
{"id": "chem-mc-246", "t": "choice", "q": "下列关于稀有气体的说法正确的是", "o": ["A. 稀有气体最外层都是8个电子", "B. 稀有气体化学性质极不活泼", "C. 稀有气体都是液态", "D. He原子最外层有8个电子"], "a": "B", "e": "稀有气体化学性质稳定，因为最外层已达稳定结构。He最外层2个电子，Ne最外层8个。稀有气体在常温下是气态。"},
{"id": "chem-mc-247", "t": "choice", "q": "下列微粒中与Ne的电子排布相同的是", "o": ["A. Na+", "B. F", "C. O2-", "D. A和C都是"], "a": "D", "e": "Ne有10个电子。Na+（11-1=10个电子）、O2-（8+2=10个电子）都有10个电子。F（9个电子）不相同。"},
{"id": "chem-mc-248", "t": "choice", "q": "下列关于第三周期元素的说法正确的是", "o": ["A. Na、Mg、Al的原子半径依次减小", "B. Si、P、S的原子半径依次增大", "C. Na、Mg、Al的金属性依次减弱", "D. Cl、S、P的非金属性依次增强"], "a": "C", "e": "第三周期Na、Mg、Al原子半径依次减小，金属性依次减弱。Si、P、S原子半径也依次减小。Cl>S>P非金属性减弱。"},
{"id": "chem-mc-249", "t": "choice", "q": "某元素R的原子序数为16，下列说法不正确的是", "o": ["A. R是硫元素", "B. R在第三周期第VIA族", "C. R的最高正价为+6", "D. R的氢化物化学式为RH4"], "a": "D", "e": "16号元素是S（硫），第三周期第VIA族，最高正价+6（如H2SO4）。氢化物为H2S，不是RH4。RH4是第IVA族氢化物。"},
{"id": "chem-mc-250", "t": "choice", "q": "下列关于元素周期表的说法正确的是", "o": ["A. 元素周期表有7个周期", "B. 元素周期表有18个族", "C. 元素周期表是按原子序数递增排列", "D. 以上都正确"], "a": "D", "e": "元素周期表有7个周期（1-7），16个族（现已改为18列），按原子序数递增排列。"},
{"id": "chem-mc-251", "t": "choice", "q": "原子序数为7的元素在元素周期表中的位置是", "o": ["A. 第二周期第VA族", "B. 第二周期第VIA族", "C. 第三周期第VA族", "D. 第一周期第VA族"], "a": "A", "e": "7号元素是氮N，电子排布为2-5，位于第二周期第VA族。"},
{"id": "chem-mc-252", "t": "choice", "q": "短周期元素中，原子最外层电子数等于电子层数的元素有", "o": ["A. H和Be", "B. H和Al", "C. H、Be、Al", "D. H、Li、Al"], "a": "C", "e": "H：1层1电子；Be：2层2电子；Al：3层3电子。C正确。Li是2层1电子，最外层不等于电子层数。"},
{"id": "chem-mc-253", "t": "choice", "q": "下列关系正确的是", "o": ["A. 酸性H2CO3>H2SiO3", "B. 碱性KOH<NaOH", "C. 稳定性HF<HCl", "D. 原子半径Na<Mg"], "a": "A", "e": "非金属性C>Si，所以最高价含氧酸酸性H2CO3>H2SiO3。碱性KOH>NaOH（K金属性>Na），稳定性HF>HCl（F非金属性>Cl），原子半径Na>Mg（同周期）。"},
{"id": "chem-mc-254", "t": "choice", "q": "下列元素中属于过渡元素的是", "o": ["A. Na", "B. Fe", "C. Cl", "D. S"], "a": "B", "e": "Fe属于过渡元素（d区元素）。Na是主族元素，Cl和S是主族元素。过渡元素包括第IIIB到IIB族。"},
{"id": "chem-mc-255", "t": "choice", "q": "某元素气态氢化物的化学式为H2R，则R的最高价氧化物的化学式为", "o": ["A. RO", "B. RO2", "C. RO3", "D. R2O5"], "a": "C", "e": "H2R中R为-2价，最外层6个电子，第VIA族，最高正价+6，最高价氧化物为RO3。如S：H2S对应SO3。"},
{"id": "chem-mc-256", "t": "choice", "q": "下列关于同周期元素的说法正确的是", "o": ["A. 最外层电子数从1到8递增", "B. 原子半径从大到小递减", "C. 金属性从弱到强递增", "D. 非金属性从强到弱递减"], "a": "B", "e": "同周期从左到右原子半径递减，金属性减弱，非金属性增强。最外层电子数从1到8（但稀有气体除外一般讨论1-7族）。"},
{"id": "chem-mc-257", "t": "choice", "q": "下列说法正确的是", "o": ["A. 原子序数越大的元素非金属性越强", "B. 电子层数越多的原子半径越大", "C. 最外层电子数越多的元素金属性越强", "D. 短周期中原子序数越大原子半径越大"], "a": "B", "e": "一般同主族电子层数越多原子半径越大，但不能跨族比较。同周期原子序数越大原子半径越小。"},
{"id": "chem-mc-258", "t": "choice", "q": "下列各组元素中，能形成AB2型化合物的是", "o": ["A. Na和Cl", "B. Mg和O", "C. Ca和Cl", "D. K和O"], "a": "C", "e": "Ca和Cl形成CaCl2（AB2型）。NaCl和MgO是AB型，K2O是A2B型。"},
{"id": "chem-mc-259", "t": "choice", "q": "下列含有离子键的是", "o": ["A. HCl", "B. NaCl", "C. H2O", "D. CO2"], "a": "B", "e": "NaCl由Na+和Cl-通过离子键结合。HCl、H2O、CO2都是由共价键结合的共价化合物。"},
{"id": "chem-mc-260", "t": "choice", "q": "下列物质中只含共价键的是", "o": ["A. NaOH", "B. Na2O2", "C. H2SO4", "D. CaCl2"], "a": "C", "e": "H2SO4中只有共价键（H-O和S-O键）。NaOH含离子键和共价键，Na2O2含离子键和非极性共价键，CaCl2只有离子键。"},
{"id": "chem-mc-261", "t": "choice", "q": "下列分子中既含极性键又含非极性键的是", "o": ["A. HCl", "B. N2", "C. H2O2", "D. CO2"], "a": "C", "e": "H2O2的结构为H-O-O-H，含H-O极性键和O-O非极性键。HCl只有极性键，N2只有非极性键，CO2只有极性键。"},
{"id": "chem-mc-262", "t": "choice", "q": "下列关于化学键的说法正确的是", "o": ["A. 只含金属元素的化合物中一定含离子键", "B. 离子化合物中一定含有离子键", "C. 共价化合物中可能含有离子键", "D. 含有离子键的化合物一定是离子化合物"], "a": "D", "e": "含有离子键的一定是离子化合物。AlCl3是只含金属元素但全是共价键的例外。离子化合物可以同时含共价键（如NaOH），共价化合物不能含离子键。"},
{"id": "chem-mc-263", "t": "choice", "q": "下列物质中既含离子键又含共价键的是", "o": ["A. KCl", "B. NaOH", "C. H2O", "D. CO2"], "a": "B", "e": "NaOH中Na+与OH-之间是离子键，OH-中O-H是共价键。KCl只有离子键，H2O和CO2只有共价键。"},
{"id": "chem-mc-264", "t": "choice", "q": "下列微粒中只含非极性键的是", "o": ["A. HCl", "B. H2O", "C. N2", "D. NH3"], "a": "C", "e": "N2中N-N键是非极性键（两个相同原子）。HCl、H2O、NH3中的键都是极性键（不同原子）。"},
{"id": "chem-mc-265", "t": "choice", "q": "下列关于共价键的说法正确的是", "o": ["A. 共价键只存在于共价化合物中", "B. 共价键只存在于分子中", "C. 离子化合物中也可能含有共价键", "D. 非极性键只存在于单质分子中"], "a": "C", "e": "离子化合物中可以含共价键，如NaOH中OH-内有共价键。共价键也存在于离子化合物（如Na2O2中的O-O键）和单质中。"},
{"id": "chem-mc-266", "t": "choice", "q": "下列分子中所有原子都满足最外层8电子结构的是", "o": ["A. PCl5", "B. BF3", "C. CO2", "D. BeCl2"], "a": "C", "e": "CO2中C形成4个共价键（满足8电子），每个O形成2个共价键（满足8电子）。PCl5中P有10个电子（超过8），BF3中B有6个电子（不足8），BeCl2中Be有4个电子。"},
{"id": "chem-mc-267", "t": "choice", "q": "下列分子中含有配位键的是", "o": ["A. NH3", "B. H2O", "C. NH4+", "D. CH4"], "a": "C", "e": "NH4+中N提供孤电子对与H+形成配位键。NH3、H2O、CH4中都是普通的共价键。"},
{"id": "chem-mc-268", "t": "choice", "q": "Na2O2中O2^2-含有的化学键类型是", "o": ["A. 只有离子键", "B. 只有共价键", "C. 离子键和非极性共价键", "D. 离子键和极性共价键"], "a": "C", "e": "Na2O2中Na+与O2^2-之间是离子键，O2^2-中两个O原子之间是非极性共价键（O-O键）。"},
{"id": "chem-mc-269", "t": "choice", "q": "下列分子中，键角最大的是", "o": ["A. H2O", "B. NH3", "C. CO2", "D. CH4"], "a": "C", "e": "CO2是直线形分子，键角180度。H2O键角约104.5度，NH3键角约107度，CH4键角109.5度。CO2键角最大。"},
{"id": "chem-mc-270", "t": "choice", "q": "下列属于离子化合物的是", "o": ["A. HCl", "B. H2SO4", "C. Na2SO4", "D. H2O"], "a": "C", "e": "Na2SO4由Na+和SO4^2-组成，是离子化合物。HCl、H2SO4、H2O都是共价化合物。"},
];
